// Banque Anatomie convertie pour le moteur sandbox.js
// Format source: { c, l, q, o, a, e }

var ALL_Q = [
  // CHAPITRE 1
  {c:"1",l:"Chap. 1",q:"Combien a-t-on de vraies côtes ?",o:["10", "7", "12", "5"],a:1,e:"Vraies côtes = 7 paires (côtes 1–7) — s'articulent directement avec le sternum."},
  {c:"1",l:"Chap. 1",q:"De quel type sont les articulations zygapophysaires au niveau lombaire ?",o:["Trochoïde", "Arthrodies", "Trochléenne", "Énarthrose"],a:1,e:"Les articulations zygapophysaires = ARTHRODIES (planes) à tous les niveaux vertébraux."},
  {c:"1",l:"Chap. 1",q:"De quel type sont les articulations costochondrales ?",o:["Arthrodie", "Condylienne", "Symphyse", "Synchondrose"],a:3,e:"Les articulations costochondrales = SYNCHONDROSE (cartilage non ossifié entre côte et cartilage costal)."},
  {c:"1",l:"Chap. 1",q:"Pendant le mouvement de nutation, sélectionnez la réponse correcte :",o:["La base du sacrum va en arrière", "Les os iliaques tournent en avant puis vers le sol", "La pointe du sacrum va en avant", "L'ischium tourne en avant et vers le ciel"],a:2,e:"Nutation : la pointe du sacrum VA EN AVANT. La base du sacrum va en arrière. L'ischium va en arrière et vers le bas."},
  {c:"1",l:"Chap. 1",q:"L'épine sciatique est :",o:["Supérieure à l'épine postérieure inférieure iliaque", "Entre les deux échancrures sciatiques", "Supérieure à la grande échancrure sciatique", "Inférieure à la petite échancrure sciatique"],a:1,e:"L'épine sciatique est ENTRE la grande et la petite échancrure sciatique."},
  {c:"1",l:"Chap. 1",q:"Quelles sont les deux types d'articulations entre C1 et C2 ?",o:["Arthrodie et trochléenne", "Trochoïde et condylienne", "Trochléenne et condylienne", "Trochoïde et arthrodie"],a:3,e:"C1–C2 : atlanto-axoïdienne médiane = TROCHOÏDE (rotation) + atlanto-axoïdiennes latérales = ARTHRODIES."},
  {c:"1",l:"Chap. 1",q:"Où peut-on trouver des processus mamillaires ?",o:["Sur les processus transverses des vertèbres thoraciques", "Sur les processus transverses des vertèbres lombaires", "Proche des zygapophysaires des vertèbres lombaires", "Proche des zygapophysaires des vertèbres thoraciques"],a:2,e:"Les processus mamillaires se trouvent proche des zygapophysaires des VERTÈBRES LOMBAIRES."},
  {c:"1",l:"Chap. 1",q:"Combien y a-t-il de vertèbres thoraciques ?",o:["7", "5", "10", "12"],a:3,e:"12 vertèbres thoraciques (T1–T12). 7 cervicales, 5 lombaires, 5 sacrées (fusionnées), 4 coccygiennes."},
  {c:"1",l:"Chap. 1",q:"Le sacrum résulte de la fusion de combien de vertèbres ?",o:["3", "5", "4", "6"],a:1,e:"Le sacrum = fusion de 5 vertèbres sacrées (S1–S5)."},
  {c:"1",l:"Chap. 1",q:"Quelle courbure vertébrale est une lordose ?",o:["Courbure lombaire", "Courbure cervicale et lombaire", "Courbure thoracique", "Courbure sacrée"],a:1,e:"Les LORDOSES (concavité postérieure) sont cervicale et lombaire. Les CYPHOSES (concavité antérieure) sont thoracique et sacrée."},
  {c:"1",l:"Chap. 1",q:"Les côtes flottantes sont les côtes :",o:["11 et 12", "8 à 10", "1 à 5", "1 à 7"],a:0,e:"Côtes FLOTTANTES = 11 et 12 (n'ont aucune connexion avec le sternum ni avec une autre côte par du cartilage)."},
  {c:"1",l:"Chap. 1",q:"L'atlas (C1) se distingue des autres vertèbres car il :",o:["A deux facettes articulaires inférieures convexes", "Présente des processus mamillaires", "N'a pas de corps vertébral", "A un processus épineux très long"],a:2,e:"L'atlas (C1) n'a PAS de corps vertébral. Il est remplacé par un arc antérieur qui s'articule avec la dent de l'axis."},
  // CHAPITRE 2
  {c:"2",l:"Chap. 2",q:"La suture lambdoïde est établie entre les os :",o:["Temporal et pariétal", "Pariétal et occipital", "Frontal et pariétal", "Les deux pariétaux"],a:1,e:"Suture lambdoïde = PARIÉTAUX + OCCIPITAL. Coronale = frontal + pariétaux. Sagittale = entre les deux pariétaux."},
  {c:"2",l:"Chap. 2",q:"Laquelle des affirmations concernant le splanchnocrâne est VRAIE ?",o:["Les os paires sont : maxillaires, palatins, zygomatiques, nasaux, unguis, cornets inf.", "Les os impaires sont le vomer, le palatin et l'ethmoïde", "2 impaires et 4 paires", "Il est constitué de 8 os"],a:0,e:"Splanchnocrâne : os PAIRES = maxillaires + palatins + zygomatiques + nasaux + unguis + cornets inf. Os impaires = mandibule + vomer."},
  {c:"2",l:"Chap. 2",q:"Dans quelle vue se trouve l'astérion ?",o:["Antérieure", "Postérieure", "Supérieure", "Latérale"],a:3,e:"L'astérion est un point craniométrique situé en vue LATÉRALE, à la jonction des os temporal, occipital et pariétal."},
  {c:"2",l:"Chap. 2",q:"La mandibule s'articule avec lequel des os suivants ?",o:["Maxillaire", "Sphénoïde", "Temporal", "Zygomatique"],a:2,e:"La mandibule s'articule avec le TEMPORAL = ATM (articulation temporo-mandibulaire)."},
  {c:"2",l:"Chap. 2",q:"Par quel foramen passe le système nerveux central ?",o:["Le foramen ovale", "Le canal hypoglosse", "Le foramen épineux", "Le foramen magnum"],a:3,e:"Le système nerveux central (bulbe rachidien / moelle épinière) passe par le FORAMEN MAGNUM."},
  {c:"2",l:"Chap. 2",q:"Le neurocrane est composé de combien d'os chez l'adulte ?",o:["7", "9", "6", "8"],a:3,e:"Neurocrane = 8 os : frontal + occipital + sphénoïde + ethmoïde + 2 pariétaux + 2 temporaux."},
  {c:"2",l:"Chap. 2",q:"La fosse crânienne postérieure contient :",o:["Les lobes temporaux", "Les lobes frontaux", "Le cervelet et le tronc cérébral", "Le cerveau et le cervelet"],a:2,e:"Fosse crânienne POSTÉRIEURE = cervelet + tronc cérébral. Antérieure = lobes frontaux. Moyenne = lobes temporaux."},
  // CHAPITRE 3
  {c:"3",l:"Chap. 3",q:"Lequel de ces muscles ne présente pas d'insertion sur la scapula ?",o:["Petit rhomboïde", "Scalène postérieur", "Trapèze", "Omohyoïdien"],a:1,e:"Scalène postérieur → 2e côte. L'omohyoïdien ORIGINE sur la scapula."},
  {c:"3",l:"Chap. 3",q:"Lequel ne fait PAS partie des muscles érecteurs de la colonne ?",o:["L'inter-épineux", "L'iliocostal", "Le longissimus", "L'épineux"],a:0,e:"Érecteurs = Ilio-costal + Longissimus + Épineux. L'inter-épineux = muscle intersegmentaire."},
  {c:"3",l:"Chap. 3",q:"Quelle est l'origine/insertion de l'oblique inférieur des sous-occipitaux ?",o:["Tubercule post. atlas → ligne nucale inf.", "Apoph. épineuse axis → ligne nucale inf.", "Processus transverse atlas → entre lignes nuchales", "Apoph. épineuse axis → processus transverse atlas"],a:3,e:"Oblique INF. : épi. AXIS (C2) → apoph. transverse ATLAS (C1). Seul sous-occipital sans insertion sur l'occipital."},
  {c:"3",l:"Chap. 3",q:"Lequel n'est PAS innervé par les rameaux postérieurs des nerfs spinaux ?",o:["Longissimus", "Ilio-costal", "Trapèze", "Inter-transversaire"],a:2,e:"TRAPÈZE = nerf ACCESSOIRE XI + C3–C4. Inter-transversaires = rameaux ventraux."},
  {c:"3",l:"Chap. 3",q:"Quels muscles vont d'une apophyse transverse à l'épineuse de 3 ou 4 vertèbres au-dessus ?",o:["Le rotateur court", "Le semi-épineux", "Le multifide", "Le rotateur long"],a:2,e:"MULTIFIDES : apoph. transverse → apoph. épineuse 3–4 vertèbres au-dessus."},
  {c:"3",l:"Chap. 3",q:"L'innervation motrice du trapèze est assurée par :",o:["Nerf dorsal scapula C4–C5", "Nerf thoracodorsal C6–C8", "Nerf accessoire XI + proprioception C3–C4", "Plexus cervical C2–C4"],a:2,e:"Trapèze = nerf ACCESSOIRE XI (motricité) + C3–C4 (proprioception)."},
  {c:"3",l:"Chap. 3",q:"L'ordre des érecteurs de latéral à médial est :",o:["Ilio-costale → Épineux → Longissimus", "Ilio-costale → Longissimus → Épineux", "Épineux → Longissimus → Ilio-costale", "Longissimus → Ilio-costale → Épineux"],a:1,e:"De latéral à médial : ILE (Ilio-costale → Longissimus → Épineux)."},
  {c:"3",l:"Chap. 3",q:"Les 4 origines du grand dorsal sont :",o:["Épi. T6–L4, sacrum, crête iliaque, côtes IX–XI", "Épi. T7–L3, sacrum, épine iliaque, côtes IX–XII", "Épi. T7–L5, sacrum, crête iliaque, côtes X–XII", "Épi. T5–L5, coccyx, crête iliaque, côtes VIII–X"],a:2,e:"Grand dorsal : épi. T7–L5 + sacrum + crête iliaque + côtes X–XII."},
  {c:"3",l:"Chap. 3",q:"Le petit droit postérieur de la tête prend origine sur :",o:["Apoph. transverse atlas C1", "Apoph. épineuse C3", "Apoph. épineuse axis C2", "Tubercule postérieur atlas C1"],a:3,e:"Petit droit post. : tubercule post. ATLAS (C1) → occipital partie méd. Action : extension tête uniquement."},
  {c:"3",l:"Chap. 3",q:"Les multifides sautent combien de vertèbres ?",o:["5 à 6", "3 à 4", "1 à 2", "Plus de 4 (6–8)"],a:1,e:"Multifides = 3–4 vertèbres. Rotateurs courts = 1. Rotateurs longs = 2. Semi-épineux = plus de 4."},
  {c:"3",l:"Chap. 3",q:"Quelle est l'action du splénius en contraction BILATÉRALE ?",o:["Rotation homolatérale", "Inclinaison latérale", "Extension du cou", "Flexion du cou"],a:2,e:"Bilatéral = EXTENSION du cou. Unilatéral = rotation homolatérale + inclinaison."},
  {c:"3",l:"Chap. 3",q:"Les intertransversaires sont innervés par :",o:["Nerf accessoire XI", "Branches dorsales", "Nerf dorsal scapula", "Branches ventrales"],a:3,e:"Exception : intertransversaires = branches VENTRALES. Tous les autres intrinsèques du dos = branches dorsales."},
  // CHAPITRE 4
  {c:"4",l:"Chap. 4",q:"Quel muscle NE S'ORIGINE PAS à la partie basilaire de l'occipital ?",o:["Long de la tête", "Droit antérieur de la tête", "Long du cou", "Splénius de la tête"],a:3,e:"Le splénius de la TÊTE S'INSÈRE sur l'occipital (ne prend pas origine là)."},
  {c:"4",l:"Chap. 4",q:"Le SCM n'intervient PAS dans :",o:["L'inclinaison de la tête", "L'extension de la tête", "La rotation de la tête", "L'inspiration accessoire"],a:1,e:"Le SCM ne fait PAS l'extension de la tête. Il fait : flexion (bilat.) + rotation contro. + inclinaison homo. + inspiration accessoire."},
  {c:"4",l:"Chap. 4",q:"Lequel est le plus superficiel ?",o:["Sterno-thyroïdien", "Sterno-hyoïdien", "Thyro-hyoïdien", "Long du cou"],a:1,e:"Le STERNO-HYOÏDIEN est le muscle infra-hyoïdien le plus SUPERFICIEL."},
  {c:"4",l:"Chap. 4",q:"Affirmation FAUSSE sur les nerfs des muscles supra-hyoïdiens :",o:["Mylo-hyoïdien → nerf mylohyoïdien", "Ventre ant. digastrique → nerf facial", "Génio-hyoïdien → hypoglosse", "Stylo-hyoïdien → nerf facial"],a:1,e:"FAUX : ventre ANT. digastrique = nerf MYLOHYOÏDIEN (V). Ventre POST. = facial (VII)."},
  {c:"4",l:"Chap. 4",q:"Lequel N'EST PAS un muscle infra-hyoïdien ?",o:["Sterno-thyroïde", "Sterno-hyoïde", "Omo-hyoïde", "Stylo-hyoïdien"],a:3,e:"STYLO-HYOÏDIEN = muscle SUPRA-hyoïdien (innervé par facial VII)."},
  {c:"4",l:"Chap. 4",q:"Le thyrohyoïdien est innervé par :",o:["Nerf accessoire XI", "Anse cervicale C1–C3 uniquement", "Anse cervicale + hypoglosse XII", "Nerf facial VII"],a:2,e:"Thyrohyoïdien = anse cervicale + hypoglosse XII. Seul infra-hyoïdien innervé par le XII."},
  {c:"4",l:"Chap. 4",q:"Le scalène postérieur s'insère sur :",o:["1ère côte", "3e côte", "2e côte", "Apoph. transverse C7"],a:2,e:"Scalène post. : C4–C6 → 2e côte. Scalènes ant. et moyen → 1ère côte."},
  {c:"4",l:"Chap. 4",q:"Qu'est-ce qui passe dans le triangle interscalénique ?",o:["Plexus brachial + artère sous-clavière", "Artère carotide + nerf vague", "Nerf phrénique + artère sous-clavière", "Veine jugulaire + nerf phrénique"],a:0,e:"Triangle interscalénique (entre scalène ant. et moyen) : PLEXUS BRACHIAL + ARTÈRE SOUS-CLAVIÈRE."},
  {c:"4",l:"Chap. 4",q:"Le SCM en contraction unilatérale :",o:["Flexion + inclinaison controlatérale", "Extension + rotation controlatérale", "Rotation controlatérale + inclinaison homolatérale", "Flexion + rotation homolatérale"],a:2,e:"SCM unilatéral : rotation CONTRO. + inclinaison HOMO. Bilatéral : flexion tête."},
  {c:"4",l:"Chap. 4",q:"Le long du cou en contraction unilatérale produit :",o:["Flexion + rotation homolatérale", "Rotation controlatérale + inclinaison", "Rotation homolatérale", "Extension cervicale"],a:1,e:"Long du cou unilatéral = inclinaison + rotation CONTROLATÉRALE. Bilatéral = flexion cervicale."},
  // CHAPITRE 5
  {c:"5",l:"Chap. 5",q:"Quel muscle de l'ATM s'insère sur le disque ?",o:["Ptérygoïdien latéral", "Temporal", "Masséter", "Ptérygoïdien médial"],a:0,e:"Ptérygoïdien LATÉRAL = seul masticateur qui s'insère sur le disque + col mandibule + capsule."},
  {c:"5",l:"Chap. 5",q:"Les muscles masticateurs sont innervés par :",o:["Le nerf accessoire", "Le nerf mandibulaire (V3)", "Le nerf vague", "Le nerf facial"],a:1,e:"Tous les masticateurs = NC V branche MANDIBULAIRE (V3)."},
  {c:"5",l:"Chap. 5",q:"Lors de l'ouverture de la bouche, le ménisque :",o:["Avance", "Recule", "Se déplace latéralement", "Reste au même endroit"],a:0,e:"À l'ouverture : le ménisque AVANCE sur le tubercule articulaire."},
  {c:"5",l:"Chap. 5",q:"Lequel n'a PAS pour fonction d'abaisser la mâchoire ?",o:["Digastrique", "Stylo-hyoïdien", "Mylohyoïdien", "Géniohyoïdien"],a:1,e:"STYLO-HYOÏDIEN élève et repositionne l'hyoïde."},
  {c:"5",l:"Chap. 5",q:"Lequel a pour action 'souffler' ?",o:["Abaisseur de l'angle de la bouche", "Orbiculaire de la bouche", "Buccinateur", "Risorius"],a:2,e:"Le BUCCINATEUR est le muscle qui permet de souffler. Il est recouvert par le masséter."},
  {c:"5",l:"Chap. 5",q:"Les fibres postérieures du temporal réalisent :",o:["La diduction", "La protrusion", "La rétraction de la mandibule", "L'élévation de la mandibule"],a:2,e:"Fibres POST. temporal = RÉTRACTION mandibule. Fibres ant. + moy. = élévation."},
  {c:"5",l:"Chap. 5",q:"Le masséter s'insère sur :",o:["Face latérale branche mandibule", "Col mandibule", "Apophyse coronoïde", "Fosse ptérygoïdienne"],a:0,e:"Masséter : arcade zygomatique → face LATÉRALE branche mandibule."},
  {c:"5",l:"Chap. 5",q:"Le ligament temporo-mandibulaire latéral protège :",o:["Le nerf auriculotemporal", "La fosse ptérygoïdienne", "Le méat acoustique externe + limite mvt arrière", "L'articulation des mvt vers l'avant"],a:2,e:"Lig. temporo-mand. lat. : arcade zygomatique → col mandibule. Limite mvt ARRIÈRE + protège méat acoustique externe."},
  {c:"5",l:"Chap. 5",q:"La classification fonctionnelle de l'ATM est :",o:["Ginglymo-arthrodiale (charnière + glissement)", "Arthrodie + trochoïde", "Trochoïde + condylienne", "Énarthrose + condylienne"],a:0,e:"ATM = ginglymo-arthrodiale. Ginglyme = charnière. Arthrodiale = glissement."},
  // THÈME 6
  {c:"6",l:"Thème 6",q:"Lequel de ces muscles est inspirateur ?",o:["Ils sont tous inspirateurs", "Dentelé postérieur inférieur", "Transverse du thorax", "Dentelé postérieur supérieur"],a:3,e:"Dentelé post. SUP. = INSPIRATEUR (élève côtes II–V). Post. INF. = expirateur."},
  {c:"6",l:"Thème 6",q:"Sur laquelle le diaphragme NE s'insère PAS ?",o:["Apophyse xiphoïde", "Côtes 7 à 12", "Corps vertébraux L1–L3", "Apophyse transverse de T12"],a:3,e:"Diaphragme ne s'insère PAS sur l'apophyse TRANSVERSE de T12."},
  {c:"6",l:"Thème 6",q:"L'origine lombaire du diaphragme :",o:["Permet le passage du psoas sous le lig. arqué latéral", "Permet le passage de la veine cave", "Présente deux piliers sur les vertèbres thoraciques", "Permet le passage du psoas sous le lig. arqué médial"],a:3,e:"Lig. arqué MÉDIAL = passage du PSOAS. Lig. arqué LATÉRAL = passage du carré des lombes."},
  {c:"6",l:"Thème 6",q:"Réponse FAUSSE par rapport au diaphragme :",o:["Innervé par le nerf phrénique", "La contraction augmente le volume interne", "Présente un foramen pour veine cave, aorte et œsophage", "Sépare la cavité abdominale du pelvis"],a:3,e:"FAUX : le diaphragme sépare la cavité THORACIQUE de la cavité ABDOMINALE."},
  {c:"6",l:"Thème 6",q:"Par rapport au diaphragme, indiquez la bonne réponse :",o:["Tout ce qui précède est correct", "Il est situé entre cavité thoracique et abdominale", "Il est inspirateur", "Son insertion est le centre phrénique"],a:0,e:"TOUT EST CORRECT : localisation thoraco-abdominale + centre phrénique = tendon central + inspirateur."},
  {c:"6",l:"Thème 6",q:"À quel niveau passe l'aorte dans le diaphragme ?",o:["T8", "T6", "T10", "T12"],a:3,e:"T12 = aorte + canal thoracique + veine azygos. T8 = veine cave. T10 = œsophage."},
  {c:"6",l:"Thème 6",q:"Le faisceau neurovasculaire intercostal passe entre :",o:["Externes et internes", "Internes et intimes", "Intimes et plèvre", "Externes et plèvre"],a:1,e:"Faisceau neurovasculaire = entre intercostaux INTERNES et INTIMES."},
  {c:"6",l:"Thème 6",q:"Le ligament arqué LATÉRAL du diaphragme est en rapport avec :",o:["L'aorte", "Le carré des lombes", "La veine cave inférieure", "Le psoas"],a:1,e:"Lig. arqué LATÉRAL = carré des lombes. Lig. arqué MÉDIAL = psoas."},
  {c:"6",l:"Thème 6",q:"Le pilier DROIT du diaphragme s'insère sur :",o:["L1–L3", "L2–L4", "L1–L4", "L1–L2"],a:0,e:"Pilier DROIT : L1–L3. Pilier GAUCHE : L1–L2. Le droit est plus long (entoure l'œsophage)."},
  {c:"6",l:"Thème 6",q:"Les intercostaux internes s'étendent :",o:["De l'angle costal au sternum", "Du tubercule costal aux cartilages costaux", "De l'angle costal à 5–6 cm du sternum", "De la tête costale à l'angle costal"],a:0,e:"Intercostaux INTERNES : angle costal → sternum. EXTERNES : tubercule costal → cartilages costaux."},
  {c:"6",l:"Thème 6",q:"L'innervation du diaphragme est assurée par :",o:["Anse cervicale C1–C3", "Nerf phrénique C3–C5", "Branches post. C4–C6", "Nerfs intercostaux T6–T12"],a:1,e:"Diaphragme = nerf PHRÉNIQUE C3–C5."},
  // CHAPITRE 7
  {c:"7",l:"Chap. 7",q:"Concernant le droit de l'abdomen au-dessus des EIAS :",o:["Il est entouré par l'aponévrose de l'oblique interne", "Il est postérieur à l'aponévrose du transverse", "Il est postérieur à l'aponévrose de l'oblique interne", "Il est antérieur à l'aponévrose de l'oblique externe"],a:0,e:"Au-dessus EIAS : le grand droit est ENTOURÉ (feuillet ant. = oblique ext. + ½ oblique int. / post. = ½ oblique int. + transverse)."},
  {c:"7",l:"Chap. 7",q:"Par les fibres de quel muscle est formé le CRÉMASTER ?",o:["Oblique interne", "Droit de l'abdomen", "Oblique externe", "Transverse"],a:0,e:"Crémaster = fibres de l'OBLIQUE INTERNE qui descendent vers le testicule."},
  {c:"7",l:"Chap. 7",q:"Pour une flexion + rotation de tronc vers la gauche :",o:["Oblique ext. homo. + oblique int. contro.", "Seulement l'oblique interne", "Toutes les réponses sont fausses", "Oblique ext. contro. + oblique int. homo."],a:3,e:"Rotation gauche = oblique ext. DROIT (contro.) + oblique int. GAUCHE (homo.). E-C / I-H."},
  {c:"7",l:"Chap. 7",q:"Avec quel muscle l'oblique externe s'interdigite ?",o:["Ce n'est pas l'externe mais l'interne", "Grand dorsal + grand pectoral", "Dentelé antérieur + grand pectoral", "Grand dorsal + dentelé antérieur"],a:3,e:"Oblique externe s'interdigite avec GRAND DORSAL + DENTELÉ ANTÉRIEUR."},
  {c:"7",l:"Chap. 7",q:"La ligne arquée de Douglas est :",o:["La limite inférieure de la paroi postérieure de la gaine", "La limite supérieure de la gaine du droit", "La jonction des aponévroses sur la ligne médiane", "Le bord inférieur du lig. inguinal"],a:0,e:"Ligne arquée = limite INFÉRIEURE de la paroi POSTÉRIEURE de la gaine du droit."},
  {c:"7",l:"Chap. 7",q:"Le ligament inguinal est formé par :",o:["Bord inférieur épaissi aponévrose oblique externe", "Bord inférieur aponévrose du transverse", "Bord supérieur aponévrose oblique interne", "Bord supérieur aponévrose oblique externe"],a:0,e:"Lig. inguinal = bord inf. épaissi aponévrose OBLIQUE EXTERNE. De l'EIAS au tubercule pubien."},
  {c:"7",l:"Chap. 7",q:"Le canal inguinal contient chez la femme :",o:["Le ligament rond de l'utérus", "Le nerf ilio-inguinal", "L'artère épigastrique inférieure", "Le cordon spermatique"],a:0,e:"Canal inguinal ♀ = LIGAMENT ROND de l'utérus. ♂ = cordon spermatique."},
  {c:"7",l:"Chap. 7",q:"L'oblique interne en contraction unilatérale réalise :",o:["Rotation controlatérale", "Compression des viscères", "Extension du tronc", "Rotation homolatérale"],a:3,e:"Oblique interne unilatéral = rotation HOMOLATÉRALE. Mnémotechnique : I-H."},
  {c:"7",l:"Chap. 7",q:"Quelle est la fonction principale du transverse de l'abdomen ?",o:["Rotation controlatérale", "Flexion du tronc", "Compression et soutien des viscères", "Inclinaison latérale"],a:2,e:"Transverse = COMPRESSION + soutien viscères + maintien pression intra-abdominale."},
  {c:"7",l:"Chap. 7",q:"La ligne blanche s'étend de :",o:["L'apophyse xiphoïde au pubis", "L'EIAS au pubis", "La crête iliaque au pubis", "La 7e côte au pubis"],a:0,e:"Ligne blanche : xiphoïde → pubis. Jonction des 3 aponévroses controlatérales."},
  // CHAPITRE 8
  {c:"8",l:"Chap. 8",q:"Lequel se trouve dans le plan moyen (diaphragme urogénital) ?",o:["Sphincter externe de l'anus", "Pubo-rectal", "Bulbo-spongieux", "Transverse profond du périnée"],a:3,e:"Plan MOYEN = transverse PROFOND du périnée + sphincter urétral."},
  {c:"8",l:"Chap. 8",q:"Lequel NE s'insère PAS sur le centre tendineux du périnée ?",o:["Transverse superficiel du périnée", "Ischio-caverneux", "Sphincter de l'anus", "Bulbo-spongieux"],a:1,e:"L'ISCHIO-CAVERNEUX s'insère sur la base du pénis/clitoris, pas sur le corps périnéal."},
  {c:"8",l:"Chap. 8",q:"Lequel est un faisceau du muscle élévateur de l'anus ?",o:["Pubo-coccygien", "Ano-coccygien", "Coccygien", "Sacro-coccygien"],a:0,e:"Élévateur de l'anus = puborectal + PUBOCOCCYGIEN + iliococcygien. Le coccygien est un muscle séparé."},
  {c:"8",l:"Chap. 8",q:"Lequel de ces muscles est le plus antérieur ?",o:["Sphincter externe de l'anus", "Transverse superficiel du périnée", "Ischio-caverneux", "Coccygien"],a:2,e:"L'ISCHIO-CAVERNEUX est le plus antérieur (s'insère sur la base du pénis/clitoris)."},
  {c:"8",l:"Chap. 8",q:"Le nerf pudendal sort par quel foramen ?",o:["Foramen obturateur", "Foramen sacré", "Grand foramen sciatique", "Petit foramen sciatique"],a:2,e:"Nerf pudendal SORT par le grand foramen sciatique et ENTRE par le petit foramen sciatique → canal d'Alcock."},
  {c:"8",l:"Chap. 8",q:"Les 3 faisceaux de l'élévateur de l'anus sont :",o:["Puborectal + pubococcygien + iliococcygien", "Puborectal + iliococcygien + coccygien", "Puborectal + ischiococcygien + pubococcygien", "Ilio-coccygien + ischio-coccygien + pubo-coccygien"],a:0,e:"Élévateur de l'anus = puborectal + pubococcygien + iliococcygien."},
  {c:"8",l:"Chap. 8",q:"Le périnée a la forme d'un :",o:["Carré", "Losange", "Hexagone", "Triangle"],a:1,e:"Périnée = LOSANGE. Limites : symphyse pubienne + lig. sacro-tubéreux + tubérosités ischiatiques + sacrum."},
  {c:"8",l:"Chap. 8",q:"Le sac de Douglas se trouve :",o:["Entre vessie et utérus", "Entre rectum et sacrum", "Entre utérus et rectum", "Entre vessie et rectum"],a:2,e:"Sac de Douglas = sac recto-utérin entre l'utérus et le rectum chez la femme."},
  {c:"8",l:"Chap. 8",q:"Le ligament le plus important pour stabiliser l'utérus est :",o:["Ligament cardinal", "Ligament pubo-cervical", "Ligament large", "Ligament utéro-sacré"],a:0,e:"Ligament CARDINAL = le plus important. Col utérus → paroi pelvienne latérale."},
  // CHAPITRE 9
  {c:"9",l:"Chap. 9",q:"La moelle épinière se termine normalement entre :",o:["L2 et L3", "T12 et L1", "L3 et L4", "L1 et L2"],a:3,e:"Chez l'adulte, la moelle se termine entre L1 et L2. En dessous = queue de cheval."},
  {c:"9",l:"Chap. 9",q:"L'espace épidural contient :",o:["Le LCR", "La pie-mère", "Tissu conjonctif + graisse + plexus veineux", "Le nerf phrénique"],a:2,e:"Espace épidural = entre dure-mère et os. Contient tissu conjonctif + graisse + plexus veineux."},
  {c:"9",l:"Chap. 9",q:"Combien y a-t-il de paires de nerfs rachidiens ?",o:["28", "29", "33", "31"],a:3,e:"31 paires : 8C + 12T + 5L + 5S + 1Co."},
  {c:"9",l:"Chap. 9",q:"La méningé la plus interne est :",o:["La pie-mère", "Le LCR", "La dure-mère", "L'arachnoïde"],a:0,e:"Pie-mère = la plus interne, collée à la moelle. Arachnoïde = intermédiaire. Dure-mère = la plus externe."},
  {c:"9",l:"Chap. 9",q:"La racine postérieure d'un nerf rachidien est :",o:["Végétative", "Mixte", "Motrice", "Sensitive"],a:3,e:"Racine POSTÉRIEURE = sensitive. Racine ANTÉRIEURE = motrice."},
  {c:"9",l:"Chap. 9",q:"Le bord antérieur du foramen intervertébral est formé par :",o:["Le disque intervertébral", "Le ligament jaune", "Les processus articulaires", "Les pédicules"],a:0,e:"Bord ANT. = disque intervertébral. Bord POST. = processus articulaires + articulation zygapophysaire."},
  {c:"9",l:"Chap. 9",q:"Le nerf phrénique est issu de :",o:["C2–C4", "C1–C3", "C3–C5", "C4–C6"],a:2,e:"Nerf phrénique = C3–C5. Mnémotechnique : C3-C4-C5 keep the diaphragm alive !"},
  {c:"9",l:"Chap. 9",q:"La queue de cheval est formée par :",o:["Les racines L2–S5", "Le filum terminale", "Les nerfs sacrés uniquement", "La moelle épinière sous L1"],a:0,e:"Queue de cheval = racines nerveuses L2–S5 qui descendent dans le canal rachidien."},
  {c:"9",l:"Chap. 9",q:"La rachianesthésie injecte dans :",o:["Le canal central", "Entre dure-mère et arachnoïde", "L'espace épidural", "L'espace sous-arachnoïdien"],a:3,e:"Rachianesthésie = espace SOUS-ARACHNOÏDIEN. Péridurale = espace épidural."},
  // CHAPITRE 2.2
  {c:"22",l:"Chap. 2.2",q:"Quel est le type de l'articulation coxo-fémorale ?",o:["Énarthrose", "Condylienne", "Trochoïde", "Plane"],a:0,e:"Coxo-fémorale = ÉNARTHROSE (sphérique), 3 degrés de liberté."},
  {c:"22",l:"Chap. 2.2",q:"Proposition VRAIE à propos du lig. ilio-fémoral ?",o:["Se tend en flexion + stabilise en position quadrupède", "Se tend en extension + stabilise en position bipède", "Se tend en flexion + stabilise en position bipède", "Se tend en extension + stabilise en position quadrupède"],a:1,e:"Lig. ilio-fémoral : se tend en EXTENSION → maintien posture BIPÈDE."},
  {c:"22",l:"Chap. 2.2",q:"Lequel a la plus grande amplitude articulaire à la hanche ?",o:["Abduction", "Rotation externe", "Extension", "Flexion"],a:3,e:"Flexion hanche = 120° = la plus grande amplitude."},
  {c:"22",l:"Chap. 2.2",q:"Affirmation FAUSSE à propos de la flexion de hanche ?",o:["Le lig. pubo-fémoral limite le mouvement", "Le psoas-iliaque participe", "Amplitude plus importante avec genou en flexion", "Le sartorius participe"],a:0,e:"FAUX : lig. PUBO-FÉMORAL limite l'ABDUCTION + rotation lat., pas la flexion."},
  {c:"22",l:"Chap. 2.2",q:"Le lig. ischio-fémoral limite la rotation interne de hanche ?",o:["Vrai","Faux"],a:0,e:"VRAI. Le lig. ischio-fémoral limite la ROTATION MÉDIALE."},
  {c:"22",l:"Chap. 2.2",q:"Quelle action NE fait PAS le psoas-iliaque ?",o:["Flexion du tronc", "Antéversion du pelvis", "Hyperlordose lombaire", "Extension du tronc"],a:3,e:"Psoas-iliaque ne fait PAS l'extension du tronc."},
  {c:"22",l:"Chap. 2.2",q:"Action du piriforme lorsque la hanche est fléchie ?",o:["Abduction", "Rotation externe", "Rotation interne", "Adduction"],a:2,e:"Piriforme en FLEXION = rotation INTERNE + abduction."},
  {c:"22",l:"Chap. 2.2",q:"L'obturateur interne s'insère sur le petit trochanter ?",o:["Vrai","Faux"],a:1,e:"FAUX. Obturateur interne → face MÉD. GRAND trochanter. Petit trochanter = psoas-iliaque."},
  {c:"22",l:"Chap. 2.2",q:"Lequel ne s'insère PAS sur la tubérosité ischiatique ?",o:["Carré fémoral", "Les jumeaux", "L'obturateur externe", "Semi-tendineux"],a:2,e:"Obturateur EXTERNE → fosse trochantérique. Les autres → tubérosité ischiatique."},
  {c:"22",l:"Chap. 2.2",q:"Moyen glutéal et grand glutéal ont la même innervation ?",o:["Vrai","Faux"],a:1,e:"FAUX. Moyen glutéal = nerf glutéal SUPÉRIEUR. Grand glutéal = nerf glutéal INFÉRIEUR."},
  {c:"22",l:"Chap. 2.2",q:"Le ligament pubo-fémoral limite :",o:["L'abduction et la rotation latérale", "La flexion et l'adduction", "L'extension et la rotation latérale", "La flexion et la rotation médiale"],a:0,e:"Lig. pubo-fémoral : branche pubienne → fosse intertrochantérienne. Limite ABDUCTION + rotation LATÉRALE."},
  {c:"22",l:"Chap. 2.2",q:"Le psoas-iliaque s'insère sur :",o:["Le petit trochanter", "La tubérosité glutéale", "La ligne intertrochantérienne", "Le grand trochanter"],a:0,e:"Psoas-iliaque : T12–L5 + fosse iliaque → PETIT trochanter."},
  // CHAPITRE 2.3
  {c:"23",l:"Chap. 2.3",q:"De quel type est l'articulation du genou ?",o:["Symphyse", "Trochlée modifiée", "Condylienne", "Trochoïde"],a:1,e:"Genou = synoviale en TROCHLÉE MODIFIÉE. 2 degrés : flexion/extension + rotation axiale."},
  {c:"23",l:"Chap. 2.3",q:"Concernant les cavités glénoïdes du tibia :",o:["Latérale concave transv. + convexe antéropost.", "Médiale concave transv. + convexe antéropost.", "Médiale concave antéropost. + convexe transv.", "Les deux concaves dans tous les plans"],a:0,e:"Cavité glénoïde LATÉRALE = concave transv. + CONVEXE antéropost. Médiale = concave dans les DEUX plans."},
  {c:"23",l:"Chap. 2.3",q:"La capsule condylienne du genou :",o:["Adhère avec les deux", "Adhère avec le ménisque latéral", "Adhère avec le ménisque médial", "N'adhère avec aucun"],a:1,e:"La capsule adhère avec le ménisque LATÉRAL. Le LCM adhère avec le ménisque médial."},
  {c:"23",l:"Chap. 2.3",q:"Les ligaments croisés du genou :",o:["LCA limite la flexion", "LCP limite l'extension", "LCA se tend en flexion", "LCP est sollicité en flexion"],a:3,e:"LCP est SOLLICITÉ en FLEXION. LCA se TEND en EXTENSION."},
  {c:"23",l:"Chap. 2.3",q:"Les ligaments croisés sont :",o:["Intra-capsulaires et intra-synoviaux", "Extra-capsulaires et extra-synoviaux", "Intra-capsulaires et extra-synoviaux", "Extra-capsulaires et intra-synoviaux"],a:2,e:"LCA + LCP = INTRA-capsulaires + EXTRA-synoviaux."},
  {c:"23",l:"Chap. 2.3",q:"Rotation externe du tibia = rotation interne du genou ?",o:["Vrai","Faux"],a:0,e:"VRAI. Rotations tibia/genou sont inverses."},
  {c:"23",l:"Chap. 2.3",q:"Tout le quadriceps est bi-articulaire ?",o:["Vrai","Faux"],a:1,e:"FAUX. Seul le DROIT FÉMORAL est biarticulaire. Les 3 vastes = monoarticulaires."},
  {c:"23",l:"Chap. 2.3",q:"Lequel ne fait PAS parti de la patte d'oie superficielle ?",o:["Gracile", "Semi-tendineux", "Sartorius", "Semi-membraneux"],a:3,e:"SEMI-MEMBRANEUX = patte d'oie PROFONDE (3 tendons). Superficielle = Sartorius + Gracile + Semi-tendineux."},
  {c:"23",l:"Chap. 2.3",q:"L'amplitude de la flexion active du genou est de :",o:["145°", "160°", "135°", "120°"],a:2,e:"Flexion ACTIVE = 135°. Flexion PASSIVE = 145°."},
  {c:"23",l:"Chap. 2.3",q:"Le LCA se tend principalement lors de :",o:["La rotation latérale", "La flexion du genou", "La rotation médiale", "L'extension du genou"],a:3,e:"LCA se tend en EXTENSION. LCP est sollicité en FLEXION."},
  {c:"23",l:"Chap. 2.3",q:"Qu'est-ce que le kyste de Baker ?",o:["Une bourse infrapatellaire enflammée", "La bourse poplitée distendue par épanchement", "Une bourse prépatellaire inflammatoire", "Un kyste osseux du condyle"],a:1,e:"Kyste de Baker = bourse POPLITÉE distendue par épanchement articulaire. Visible en fosse poplitée."},
  {c:"23",l:"Chap. 2.3",q:"Le LCM limite :",o:["Le valgus + rotation médiale", "Le varus + rotation médiale", "Le valgus + rotation latérale", "Le varus + rotation latérale"],a:2,e:"LCM : limite le VALGUS + rotation LATÉRALE. LCL : limite le VARUS + rotation MÉDIALE."},
  // CHAPITRE 2.5
  {c:"25",l:"Chap. 2.5",q:"Lequel de ces muscles est innervé par un nerf DIFFÉRENT des autres ?",o:["Le droit fémoral", "Le sartorius", "Le vaste intermédiaire", "Le psoas"],a:3,e:"PSOAS = branches directes plexus lombaire L1–L3. Sartorius + vastes + droit fémoral = nerf FÉMORAL."},
  {c:"25",l:"Chap. 2.5",q:"Lequel de ces muscles ne fait pas parti de la patte d'oie superficielle ?",o:["Semi-membraneux", "Sartorius", "Semi-tendineux", "Gracile"],a:0,e:"SEMI-MEMBRANEUX = patte d'oie PROFONDE. Superficielle = Sartorius + Gracile + Semi-tendineux."},
  {c:"25",l:"Chap. 2.5",q:"Lequel des structures suivantes ne fait PAS parti des limites du triangle de Scarpa ?",o:["Le long adducteur", "Le sartorius", "Le ligament inguinal", "Le grand adducteur"],a:3,e:"Triangle de Scarpa : limite sup. = lig. inguinal · lat. = sartorius · méd. = LONG adducteur. Grand adducteur n'est PAS une limite."},
  {c:"25",l:"Chap. 2.5",q:"Laquelle des affirmations sur les limites de la fosse poplitée est FAUSSE ?",o:["Au-dessus et latéral = le semi-membraneux", "Au-dessus et médial = le semi-tendineux", "En dessous et médial = le gastrocnémien médial", "En dessous et latéral = le gastrocnémien latéral"],a:0,e:"FAUX : au-dessus et LATÉRAL = le BICEPS FÉMORAL (pas le semi-membraneux qui est médial)."},
  {c:"25",l:"Chap. 2.5",q:"Lequel de ces muscles ne s'insère pas sur la ligne âpre ?",o:["Le vaste externe", "Le semi-membraneux", "Le grand adducteur", "L'un des chefs du biceps fémoral"],a:1,e:"Le SEMI-MEMBRANEUX s'insère sur le condyle MÉDIAL du tibia (pas sur la ligne âpre)."},
  {c:"25",l:"Chap. 2.5",q:"La partie postérieure de la cuisse est innervée par :",o:["Le nerf obturateur", "Le nerf cutané postérieur cuisse", "Le nerf sciatique", "Le nerf fémoral"],a:2,e:"Zone POST. cuisse = nerf SCIATIQUE. Zone ant. = fémoral. Zone méd. = obturateur."},
  {c:"25",l:"Chap. 2.5",q:"Le contenu du canal des adducteurs (de Hunter) est :",o:["Artère poplitée + veine poplitée + nerf tibial", "Artère + veine fémorale + nerf obturateur", "Artère + veine fémorale + nerf saphène", "Artère + veine + nerf fémoral"],a:2,e:"Canal Hunter : artère fémorale + veine fémorale + nerf SAPHÈNE."},
  {c:"25",l:"Chap. 2.5",q:"Le grand adducteur a 2 faisceaux avec 2 innervations différentes :",o:["Faisceau add. : nerf sciatique · Faisceau chond. : obturateur", "Faisceau add. : nerf obturateur · Faisceau chond. : nerf sciatique", "Faisceau add. : nerf fémoral · Faisceau chond. : obturateur", "Les deux faisceaux : nerf sciatique"],a:1,e:"Grand add. : faisceau ADDUCTEUR = nerf obturateur · faisceau CHONDYLIEN = nerf SCIATIQUE."},
  {c:"25",l:"Chap. 2.5",q:"Lequel a son insertion la plus postérieure sur l'ischion ?",o:["Le grand fessier", "Le semi-tendineux", "Le semi-membraneux", "Le biceps fémoral"],a:2,e:"SEMI-MEMBRANEUX a son insertion la plus postérieure sur la tubérosité ischiatique."},
  // CHAPITRE 2.6
  {c:"26",l:"Chap. 2.6",q:"Le court fibulaire et le long fibulaire peuvent faire une pronation du pied ?",o:["Vrai","Faux"],a:0,e:"VRAI. Court fibulaire = pronation + abduction. Long fibulaire = flexion plantaire + abduction + PRONATION."},
  {c:"26",l:"Chap. 2.6",q:"Quelle est l'innervation des muscles du groupe latéral de la jambe ?",o:["Nerf fibulaire profond", "Nerf sciatique", "Nerf fibulaire superficiel", "Nerf tibial"],a:2,e:"Groupe LATÉRAL (court + long fibulaire) = nerf FIBULAIRE SUPERFICIEL."},
  {c:"26",l:"Chap. 2.6",q:"Le muscle poplité fait une rotation externe du genou ?",o:["Vrai","Faux"],a:1,e:"FAUX. Poplité = rotation INTERNE (déverrouillage genou)."},
  {c:"26",l:"Chap. 2.6",q:"Lequel des muscles suivants ne s'insère pas sur le tendon d'Achille ?",o:["Les deux ne s'insèrent pas", "Les deux s'insèrent sur ce tendon", "Le soléaire", "Le gastrocnémien"],a:1,e:"Gastrocnémien ET soléaire s'insèrent TOUS LES DEUX sur le tendon d'Achille (calcanéen)."},
  {c:"26",l:"Chap. 2.6",q:"À quel muscle appartient cette insertion : naviculaire + cuboïde + cunéiforme + base 2e–4e métatarsien ?",o:["Tibial postérieur", "Tibial antérieur", "Court fibulaire", "Long fibulaire"],a:0,e:"TIBIAL POSTÉRIEUR. Action : INVERSION du pied."},
  {c:"26",l:"Chap. 2.6",q:"Dans la gouttière latérale du pied, le court fibulaire est en avant du long fibulaire ?",o:["Vrai","Faux"],a:0,e:"VRAI. Dans la gouttière rétromalléolaire : court fibulaire est en AVANT du long fibulaire."},
  {c:"26",l:"Chap. 2.6",q:"Laquelle des articulations suivantes est une syndesmose ?",o:["Naviculaire-cunéiforme", "Cubo-naviculaire", "Calcanéo-cuboïdienne", "Cuboïdo-cunéiforme"],a:1,e:"CUBO-NAVICULAIRE = syndesmose. Autres inter-tarsiennes = arthrodies. Calcanéo-cuboïdienne = en selle."},
  {c:"26",l:"Chap. 2.6",q:"De quel type est l'articulation sous-talienne ?",o:["Trochoïde", "Arthrodie", "Condylienne", "Trochléenne"],a:0,e:"Articulation sous-talienne = TROCHOÏDE. Axe sous-talien = axe de Henke."},
  {c:"26",l:"Chap. 2.6",q:"L'éversion est une combinaison de :",o:["Flex. dorsale + abduction + supination", "Flex. plantaire + adduction + supination", "Flex. plantaire + adduction + pronation", "Flex. dorsale + abduction + pronation"],a:3,e:"ÉVERSION = flex. dorsale + abduction + PRONATION. INVERSION = flex. plantaire + adduction + supination."},
  {c:"26",l:"Chap. 2.6",q:"Lequel des éléments n'est PAS relié avec le ligament bifurqué (de Chopart) ?",o:["Naviculaire", "Calcanéum", "Cuboïde", "Talus"],a:3,e:"Lig. bifurqué = CALCANÉUM → CUBOÏDE + NAVICULAIRE. Le TALUS n'y est pas relié."},
  {c:"26",l:"Chap. 2.6",q:"Le rétinaculum des extenseurs inférieur a une forme de :",o:["Y", "Croix", "Bande droite", "Anneau"],a:0,e:"Rétinaculum ext. INF. = forme de Y. Pointe = calcanéum. Bras sup. = malléole interne. Bras inf. = aponévrose plantaire."},
  {c:"26",l:"Chap. 2.6",q:"La trochlée talaire est plus large :",o:["Sur sa face latérale", "En avant", "En arrière", "Sur sa face médiale"],a:1,e:"Trochlée talaire = plus large EN AVANT. En flex. dorsale le talus se cale dans la mortèse = très stable."},
  {c:"26",l:"Chap. 2.6",q:"La flexion dorsale est limitée par :",o:["Le lig. calcanéo-fibulaire", "Lig. talo-fibulaire ant. + faisceaux ant. deltoïde", "Les muscles fibulaires", "Lig. talo-fibulaire post. + faisceaux post. deltoïde"],a:3,e:"Freins FLEX. DORSALE : lig. talo-fibulaire POST. + faisceaux POST. deltoïde."},
  // CHAPITRE 2.7
  {c:"27",l:"Chap. 2.7",q:"Les muscles interosseux dorsaux font :",o:["Étendent les orteils et les déplacent médialement", "Fléchissent les orteils et les déplacent médialement", "Fléchissent les orteils et les déplacent latéralement", "Étendent les orteils et les déplacent latéralement"],a:2,e:"Interosseux DORSAUX : fléchissent + déplacent LATÉRALEMENT. PLANTAIRES : fléchissent + déplacent médialement."},
  {c:"27",l:"Chap. 2.7",q:"Quel muscle fait partie du groupe central MOYEN ?",o:["Les interosseux plantaires", "Court fléchisseur des orteils", "Le carré plantaire", "Adducteur de l'hallux"],a:2,e:"Groupe central MOYEN = carré plantaire + lombricaux. Plan PROFOND = interosseux. Plan SUPERFICIEL = court fléch. orteils."},
  {c:"27",l:"Chap. 2.7",q:"L'abducteur de l'hallux est innervé par :",o:["Les nerfs plantaires latéral et médial", "Les nerfs plantaires médial et fibulaire", "Le nerf fibulaire", "Le nerf tibial"],a:0,e:"Abducteur hallux = nerfs plantaires LATÉRAL ET MÉDIAL (innervation mixte)."},
  {c:"27",l:"Chap. 2.7",q:"Le court fléchisseur des orteils s'insère sur :",o:["Phalange distale 2e–5e", "Phalange proximale 2e–5e", "Phalange moyenne 2e–5e via tendons perforés", "Base des métatarsiens"],a:2,e:"Court fléch. orteils → phalange MOYENNE via TENDONS PERFORÉS. Nerf plantaire MÉDIAL."},
  {c:"27",l:"Chap. 2.7",q:"Combien y a-t-il d'interosseux dorsaux dans le pied ?",o:["4", "3", "5", "2"],a:0,e:"Interosseux DORSAUX = 4 muscles. Interosseux PLANTAIRES = 3 muscles."},
  {c:"27",l:"Chap. 2.7",q:"L'adducteur de l'hallux possède 2 têtes. La tête transversale origine sur :",o:["Bases 2e–5e métatarsiens + cunéiforme lat.", "Cuboïde + cunéiforme latéral", "3e–5e articulations métatarso-phalangiennes", "Face inférieure calcanéum"],a:2,e:"Tête TRANSVERSALE : 3e–5e articulations MP. Tête OBLIQUE : bases 2e–5e métatarsiens + cunéif. lat. + cuboïde."},
  {c:"27",l:"Chap. 2.7",q:"L'aponévrose plantaire principale a une forme :",o:["Ovale", "Triangulaire", "Circulaire", "Rectangulaire"],a:1,e:"Aponévrose plantaire = TRIANGULAIRE. Calcanéum en post. → 5 fascicules vers les orteils."},
  {c:"27",l:"Chap. 2.7",q:"Le court extenseur de l'hallux est innervé par :",o:["Nerf plantaire médial", "Nerf tibial", "Nerf fibulaire profond", "Nerf fibulaire superficiel"],a:2,e:"Court ext. hallux = nerf FIBULAIRE PROFOND (comme tout le groupe dorsal du pied)."},
  {c:"27",l:"Chap. 2.7",q:"L'opposant du 5e orteil réalise :",o:["Flexion + adduction 5e", "Flexion + abduction 5e", "Abduction + extension 5e", "Flexion seule 5e"],a:0,e:"Opposant 5e : flexion + ADDUCTION. Abducteur 5e : flexion + ABDUCTION."},
  // CHAPITRE 2.8
  {c:"28",l:"Chap. 2.8",q:"Le plexus lombaire est formé par :",o:["Branches ant. L1–L4", "Branches ant. L1–L5", "Branches ant. L2–L5", "Branches ant. L1–S1"],a:0,e:"Plexus lombaire = branches antérieures de L1 à L4. Situé dans l'épaisseur du PSOAS."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf saphène est :",o:["Une branche du nerf tibial", "Une branche sensitive du nerf fémoral", "Une branche du nerf obturateur", "Une branche du nerf sciatique"],a:1,e:"Nerf saphène = branche terminale SENSITIVE du nerf FÉMORAL. Descend dans le canal de Hunter."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf obturateur sort du bassin par :",o:["Le petit foramen sciatique", "Le foramen sacré", "Le trou obturé", "Le grand foramen sciatique"],a:2,e:"Nerf obturateur : naît bord MÉD. psoas → sort par le TROU OBTURÉ."},
  {c:"28",l:"Chap. 2.8",q:"Le plexus sacré est situé :",o:["Dans le canal obturateur", "Dans l'épaisseur du piriforme", "Au-dessus du muscle piriforme", "En dessous du muscle piriforme"],a:2,e:"Plexus sacré = paroi pelvienne postérieure, AU-DESSUS du piriforme."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf fessier supérieur innerve :",o:["Grand glutéal uniquement", "Moyen + petit glutéal + TFL", "Grand + moyen glutéal + TFL", "Piriforme + obturateur interne"],a:1,e:"N. fessier SUPÉRIEUR : moyen glutéal + petit glutéal + TFL. N. fessier INFÉRIEUR : grand glutéal."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf fibulaire commun entoure :",o:["Le col du talus", "La tête de la fibula", "La malléole médiale", "La malléole latérale"],a:1,e:"Nerf fibulaire commun entoure la TÊTE de la fibula → fibulaire superficiel + profond."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf fibulaire profond innerve la zone :",o:["Latérale de la jambe", "Postérieure de la jambe", "Médiale de la jambe", "Antérieure de la jambe"],a:3,e:"Fibulaire PROFOND = zone ANTÉRIEURE jambe."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf plantaire médial innerve en sensitif :",o:["5e orteil + moitié lat. 4e", "2 orteils médiaux uniquement", "3 orteils et demi médiaux", "Toute la plante du pied"],a:2,e:"N. plantaire MÉDIAL sensitif : 3 orteils et demi MÉDIAUX. N. plantaire LATÉRAL sensitif : 5e + moitié lat. 4e."},
  {c:"28",l:"Chap. 2.8",q:"Dans la cuisse, la zone médiale est innervée par :",o:["Nerf sciatique", "Nerf cutané fémoral latéral", "Nerf fémoral", "Nerf obturateur"],a:3,e:"Cuisse : ANT = nerf FÉMORAL · POST = nerf SCIATIQUE · MÉD = nerf OBTURATEUR."},
  {c:"28",l:"Chap. 2.8",q:"Le tronc lombo-sacré est formé par :",o:["Branche ant. L5 + branche communicante de L4", "L4 + L5 entiers", "L4 + S1", "Branche ant. L4 + branche communicante de L5"],a:0,e:"Tronc lombo-sacré = branche ant. L5 + branche communicante de L4."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf cutané fémoral latéral est issu de :",o:["L1–L3", "L1–L2", "L2–L3", "L3–L4"],a:2,e:"N. cutané fémoral LATÉRAL = L2–L3. Sensitif face LATÉRALE de la cuisse."},
  {c:"28",l:"Chap. 2.8",q:"Quelle est la différence entre nerf fessier supérieur et inférieur ?",o:["Sup = piriforme / Inf = grand glutéal", "Sup = grand glutéal / Inf = moyen + petit glutéal + TFL", "Sup = moyen + petit glutéal + TFL / Inf = grand glutéal", "Les deux innervent tous les glutéaux"],a:2,e:"N. fessier SUP. = moyen glutéal + petit glutéal + TFL. N. fessier INF. = grand glutéal UNIQUEMENT."}
];
 
// QUESTIONS SUPPLÉMENTAIRES
var EXTRA_Q = [
  // CHAPITRE 1 extra
  {c:"1",l:"Chap. 1",q:"La vertèbre C7 se distingue des autres vertèbres cervicales car :",o:["Elle n'a pas de processus transverse", "Son processus épineux est le plus long et non bifide", "Elle s'articule avec la 1ère côte", "Elle présente un corps vertébral absent"],a:1,e:"C7 = vertèbre proéminente. Son processus épineux est le plus LONG et NON BIFIDE, contrairement aux autres cervicales."},
  {c:"1",l:"Chap. 1",q:"L'articulation sacro-iliaque est de type :",o:["Énarthrose", "Amphiarthrose (synoviale plane + syndesmose)", "Symphyse", "Trochoïde"],a:1,e:"Articulation sacro-iliaque = AMPHIARTHROSE : partie antérieure = synoviale plane + partie postérieure = syndesmose."},
  {c:"1",l:"Chap. 1",q:"Les côtes dites 'fausses' sont les côtes :",o:["1 à 7", "11 et 12", "8 à 10", "8 à 12"],a:2,e:"Côtes FAUSSES = 8, 9, 10 (s'articulent avec le sternum via les cartilages des côtes supérieures). Côtes flottantes = 11, 12."},
  {c:"1",l:"Chap. 1",q:"La symphyse pubienne est une :",o:["Syndesmose", "Synchondrose", "Synoviale plane", "Symphyse (fibrocartilage)"],a:3,e:"Symphyse pubienne = SYMPHYSE avec un disque fibrocartilagineux entre les deux os pubiens."},
  {c:"1",l:"Chap. 1",q:"Le ligament longitudinal antérieur de la colonne :",o:["Limite la flexion", "Limite l'extension", "Limite l'inclinaison", "Limite la rotation"],a:1,e:"Lig. longitudinal ANTÉRIEUR : se tend en EXTENSION → limite l'extension. Lig. longitudinal POST. : limite la flexion."},
  // CHAPITRE 2 extra
  {c:"2",l:"Chap. 2",q:"L'os ethmoïde fait partie de :",o:["Du neurocrane et du splanchnocrâne", "Uniquement du splanchnocrâne", "Ni du neurocrane ni du splanchnocrâne", "Uniquement du neurocrane"],a:0,e:"L'ethmoïde fait partie des DEUX : neurocrane (lame criblée) et splanchnocrâne (lame perpendiculaire et cornets)."},
  {c:"2",l:"Chap. 2",q:"Le foramen ovale de la base du crâne laisse passer :",o:["Le nerf facial (VII)", "L'artère méningée moyenne", "Le nerf optique (II)", "Le nerf mandibulaire (V3)"],a:3,e:"Foramen ovale = nerf MANDIBULAIRE (V3). Foramen épineux = artère méningée moyenne. Canal optique = nerf optique."},
  {c:"2",l:"Chap. 2",q:"Le bregma est :",o:["La jonction des sutures coronale et sagittale", "La jonction de 4 os : frontal, pariétal, sphénoïde, temporal", "La jonction des sutures sagittale et temporale", "La jonction des sutures lambdoïde et sagittale"],a:0,e:"BREGMA = jonction sutures CORONALE + SAGITTALE. Lambda = coronale + lambdoïde. Ptérion = jonction 4 os (temporal, pariétal, frontal, sphénoïde)."},
  {c:"2",l:"Chap. 2",q:"L'os hyoïde est unique car :",o:["C'est le seul os du corps qui ne s'articule avec aucun autre os", "C'est le seul os sans cartilage", "Il est entièrement cartilagineux", "Il s'articule uniquement avec le temporal"],a:0,e:"L'os hyoïde est le seul os du corps qui ne s'articule avec AUCUN AUTRE OS. Il est maintenu par des muscles et ligaments."},
  {c:"2",l:"Chap. 2",q:"Quel os forme la plus grande partie du palais osseux ?",o:["Os sphénoïde", "Os palatin", "Os maxillaire", "Os vomer"],a:2,e:"Le palais osseux est formé à 75% par l'OS MAXILLAIRE (palatins antérieurs) et 25% par les os palatins (partie postérieure)."},
  // CHAPITRE 3 extra
  {c:"3",l:"Chap. 3",q:"Le nerf grand occipital d'Arnold est :",o:["Branche motrice de C1", "Branche motrice de C2", "Branche sensitive de C2", "Branche sensitive de C1"],a:2,e:"Nerf grand occipital d'Arnold = branche SENSITIVE de C2. Innerve le cuir chevelu postérieur."},
  {c:"3",l:"Chap. 3",q:"L'oblique supérieur de la tête réalise :",o:["Flexion + inclinaison", "Extension + inclinaison", "Rotation homolatérale uniquement", "Extension + rotation homolatérale"],a:1,e:"Oblique SUP. : apoph. transv. atlas → occipital. Action : extension + INCLINAISON."},
  {c:"3",l:"Chap. 3",q:"L'action du grand dorsal sur l'humérus est :",o:["Extension + abduction + rotation médiale", "Flexion + adduction + rotation latérale", "Extension + adduction + rotation médiale", "Flexion + abduction + rotation latérale"],a:2,e:"Grand dorsal sur humérus : extension + ADDUCTION + rotation MÉDIALE."},
  {c:"3",l:"Chap. 3",q:"Le semi-épineux se distingue des multifides par :",o:["Un saut de 1 à 2 vertèbres", "Aucune différence", "Un saut de plus de 4 vertèbres (6–8)", "Un saut de 3 à 4 vertèbres"],a:2,e:"Semi-épineux = saut de plus de 4 vertèbres (6–8). Multifides = 3–4. Rotateurs = 1–2."},
  {c:"3",l:"Chap. 3",q:"Le rhomboïde mineur prend origine sur :",o:["Lig. nucal inf. + épi. C7–T1", "Lig. nucal sup. + occipital", "Apoph. transv. C1–C4", "Épi. T2–T5"],a:0,e:"Rhomboïde MINEUR : lig. nucal inf. + épi. C7–T1 → bord méd. scapula (1/3 sup.)."},
  // CHAPITRE 4 extra
  {c:"4",l:"Chap. 4",q:"Le droit latéral de la tête réalise :",o:["Extension + rotation homolatérale", "Rotation controlatérale", "Inclinaison de la tête uniquement", "Flexion + rotation homolatérale"],a:2,e:"Droit latéral : apoph. transv. atlas C1 → face jugulaire occipital. Action : INCLINAISON tête uniquement."},
  {c:"4",l:"Chap. 4",q:"L'omohyoïdien origine sur :",o:["Le corps du sternum", "Le bord supérieur de la scapula", "Le cartilage thyroïde", "La clavicule"],a:1,e:"Omohyoïdien : bord SUP. SCAPULA → hyoïde. Seul infra-hyoïdien ne partant pas du sternum."},
  {c:"4",l:"Chap. 4",q:"Le long de la tête s'insère sur :",o:["L'apophyse transverse de C1", "La partie basilaire de l'os occipital", "Le tubercule antérieur de l'atlas", "La ligne nucale supérieure"],a:1,e:"Long de la tête : apoph. transv. C3–C6 → partie BASILAIRE occipital. Action : flexion + inclinaison homolatérale."},
  {c:"4",l:"Chap. 4",q:"Le stylohyoïdien est innervé par :",o:["Anse cervicale", "Nerf facial (VII)", "Nerf trijumeau (V)", "Nerf hypoglosse (XII)"],a:1,e:"Stylohyoïdien = nerf FACIAL (VII). Comme le ventre postérieur du digastrique."},
  {c:"4",l:"Chap. 4",q:"Le géniohyoïdien est innervé par C1 qui chemine avec :",o:["Le nerf hypoglosse (XII)", "Le nerf trijumeau (V)", "Le nerf facial (VII)", "L'anse cervicale"],a:0,e:"Géniohyoïdien : C1 chemine avec le nerf HYPOGLOSSE (XII). Action : élève l'hyoïde vers l'avant."},
  // CHAPITRE 5 extra
  {c:"5",l:"Chap. 5",q:"Le ptérygoïdien médial s'insère sur :",o:["Face latérale branche mandibule", "Face médiale branche mandibule", "Col mandibule", "Apophyse coronoïde"],a:1,e:"Ptérygoïdien MÉDIAL → face MÉDIALE branche mandibule. (Ptéryg. latéral → col mandibule + disque)."},
  {c:"5",l:"Chap. 5",q:"Le ligament sphéno-mandibulaire fait partie de :",o:["La capsule articulaire ATM", "Le ligament collatéral fibulaire", "L'aponévrose temporale", "Le fascia interptérygoïdien"],a:3,e:"Lig. sphéno-mand. : sphénoïde → face méd. branche mandibulaire. Fait partie du FASCIA INTERPTÉRYGOÏDIEN."},
  {c:"5",l:"Chap. 5",q:"Le mouvement de latéralité de l'ATM se fait autour de :",o:["Un axe oblique", "Un axe vertical passant par un seul condyle", "Un axe sagittal passant par la symphyse", "Un axe transversal passant par les 2 condyles"],a:1,e:"Latéralité = axe VERTICAL passant par UN condyle. Le menton se déplace du côté opposé."},
  {c:"5",l:"Chap. 5",q:"Lors de la rétropulsion, quel muscle est principalement en action ?",o:["Ptérygoïdien latéral", "Fibres postérieures du temporal", "Masséter", "Fibres antérieures du temporal"],a:1,e:"Rétropulsion = fibres POSTÉRIEURES du temporal. Elles tirent le condyle et le ménisque vers l'arrière."},
  // THÈME 6 extra
  {c:"6",l:"Thème 6",q:"Le transverse thoracique (triangulaire du sternum) s'insère sur :",o:["Face post. cartilages costaux 2e–6e", "Face ant. cartilages costaux 2e–6e", "Face ext. sternum", "Bord inf. côtes 2e–6e"],a:0,e:"Transverse thoracique : face post. sternum + xiphoïde → face POST. cartilages costaux 2e–6e. Abaisse → expiration."},
  {c:"6",l:"Thème 6",q:"Le dentelé postérieur inférieur prend origine sur :",o:["Épi. T9–L2", "Épi. T11–L3", "Épi. T6–T10", "Épi. T8–L1"],a:1,e:"Dentelé post. INF. : épi. T11–L3 → bord sup. côtes IX–XII. Abaisse → expiration."},
  {c:"6",l:"Thème 6",q:"L'amplitude de la flexion dorsale de cheville est limitée par :",o:["Lig. talo-fibulaire post. + faisceaux post. deltoïde", "Lig. talo-fibulaire ant. + faisceaux ant. deltoïde", "Le lig. calcanéo-fibulaire", "Les muscles extenseurs"],a:0,e:"Freins FLEX. DORSALE : lig. talo-fibulaire POST. + faisceaux POST. deltoïde. En forcé : col du talus → contact tibia."},
  {c:"6",l:"Thème 6",q:"Le mouvement en levier de pompe concerne :",o:["Toutes les côtes", "Le diaphragme", "Les côtes inférieures", "Les côtes supérieures"],a:3,e:"Côtes SUPÉRIEURES = levier de pompe (élévation antéropostérieure). Côtes inférieures = anse de seau (élévation latérale)."},
  {c:"6",l:"Thème 6",q:"Les élévateurs des côtes sont innervés par :",o:["Nerfs intercostaux", "Branches postérieures des nerfs rachidiens", "Anse cervicale C1–C3", "Nerf phrénique C3–C5"],a:1,e:"Élévateurs des côtes = branches POSTÉRIEURES des nerfs rachidiens (contrairement aux intercostaux = branches antérieures)."},
  // CHAPITRE 7 extra
  {c:"7",l:"Chap. 7",q:"Le pyramidal s'insère sur :",o:["L'apophyse xiphoïde", "La ligne blanche", "La crête pubienne", "Le cartilage costal du 5e"],a:1,e:"Pyramidal : pubis → LIGNE BLANCHE. Action : tend la ligne blanche. Innervé par T12. Muscle inconstant."},
  {c:"7",l:"Chap. 7",q:"L'oblique externe prend origine sur :",o:["Crête iliaque + lig. inguinal", "Face interne côtes 5e–12e + apoph. transv.", "Face externe côtes 5e–12e", "Face interne des 6 dernières côtes"],a:2,e:"Oblique externe : face EXTERNE côtes 5e–12e. S'interdigite avec grand dorsal + dentelé antérieur."},
  {c:"7",l:"Chap. 7",q:"L'anneau inguinal superficiel se situe dans :",o:["L'aponévrose de l'oblique interne", "L'aponévrose du transverse", "L'aponévrose de l'oblique externe au-dessus du tubercule pubien", "La gaine du droit"],a:2,e:"Anneau inguinal superficiel = orifice dans aponévrose OBLIQUE EXTERNE, au-dessus du tubercule pubien."},
  {c:"7",l:"Chap. 7",q:"Le carré des lombes en contraction unilatérale réalise :",o:["Rotation homolatérale colonne lombaire", "Extension colonne lombaire", "Flexion colonne lombaire", "Inclinaison homolatérale colonne lombaire"],a:3,e:"Carré des lombes unilatéral = INCLINAISON HOMOLATÉRALE de la colonne lombaire."},
  {c:"7",l:"Chap. 7",q:"Le grand droit de l'abdomen prend origine sur :",o:["Crête pubienne", "Cartilages costaux 5e–7e + xiphoïde", "Ligne blanche", "Symphyse pubienne"],a:0,e:"Grand droit : O = CRÊTE PUBIENNE → I = cartilages costaux 5e–7e + xiphoïde. Ne pas inverser !"},
  // CHAPITRE 8 extra
  {c:"8",l:"Chap. 8",q:"L'élévateur de l'anus prend origine sur :",o:["Pubis + membrane obturatrice", "Ischion + sacrum + coccyx", "Pubis post. + arc tendineux fascia obturateur + épine sciatique", "Sacrum + coccyx + épine ischiatique"],a:2,e:"Élévateur de l'anus : pubis post. + arc tendineux fascia obturateur interne + épine sciatique."},
  {c:"8",l:"Chap. 8",q:"L'obturateur interne est innervé par :",o:["Branches S2–S4", "Nerf obturateur L2–L4", "Nerf obturateur interne L5–S1", "Nerf pudendal"],a:2,e:"Obturateur INTERNE = nerf obturateur interne L5–S1. À ne pas confondre avec nerf obturateur L2–L4 (adducteurs)."},
  {c:"8",l:"Chap. 8",q:"Le ligament large de l'utérus se compose de :",o:["Mésomètre + mésosalpinx + mésovarium", "Mésovarium + lig. cardinal + mésosalpinx", "Lig. rond + lig. utéro-sacré + mésomètre", "Mésomètre + lig. pubo-cervical + mésovarium"],a:0,e:"Ligament large = mésomètre + mésosalpinx (trompe) + mésovarium (ovaire)."},
  {c:"8",l:"Chap. 8",q:"Le coccygien est innervé par :",o:["Branches ant. S4 uniquement", "Nerf pudendal S2–S4", "Nerf obturateur interne", "Branches ant. S3–S4"],a:3,e:"Coccygien : branches antérieures de S3–S4. Élévateur de l'anus = branches ant. S4 + nerf pudendal S2–S4."},
  {c:"8",l:"Chap. 8",q:"Le bulbo-spongieux chez la femme réalise :",o:["Ferme le canal anal", "Stabilise le corps périnéal uniquement", "Déplace le sang vers le gland du clitoris", "Vidange résiduelle urètre"],a:2,e:"Bulbo-spongieux ♀ : déplace le sang vers le GLAND du clitoris. ♂ : vidange urètre + émission sperme."},
  // CHAPITRE 9 extra
  {c:"9",l:"Chap. 9",q:"Combien y a-t-il de paires de nerfs cervicaux ?",o:["9", "6", "8", "7"],a:2,e:"8 paires de nerfs cervicaux (C1–C8), bien que la colonne cervicale n'ait que 7 vertèbres."},
  {c:"9",l:"Chap. 9",q:"Le bord postérieur du foramen intervertébral est formé par :",o:["Les processus articulaires + articulation zygapophysaire", "Le disque intervertébral", "Le ligament jaune", "Les pédicules"],a:0,e:"Bord POST. = processus articulaires + articulation ZYGAPOPHYSAIRE. Bord ant. = disque intervertébral."},
  {c:"9",l:"Chap. 9",q:"L'anesthésie péridurale injecte dans :",o:["Le canal central", "Entre dure-mère et arachnoïde", "L'espace épidural", "L'espace sous-arachnoïdien"],a:2,e:"PÉRIDURALE = espace ÉPIDURAL. Rachianesthésie = espace sous-arachnoïdien."},
  {c:"9",l:"Chap. 9",q:"Les branches antérieures des nerfs rachidiens sont :",o:["Uniquement sensitives", "Égales aux branches post.", "Plus petites que les branches post.", "Plus grandes et innervent la plupart du corps"],a:3,e:"Branches ANTÉRIEURES = beaucoup plus grandes. Forment les plexus. Branches post. = petites, innervent le dos."},
  {c:"9",l:"Chap. 9",q:"Le crémaster est innervé par :",o:["Nerf ilio-inguinal", "Nerf obturateur", "Nerf génito-fémoral", "Nerf ilio-hypogastrique"],a:2,e:"Crémaster = nerf GÉNITO-FÉMORAL (L1–L2). Responsable du réflexe crémastérien."},
  // CHAPITRE 2.2 extra
  {c:"22",l:"Chap. 2.2",q:"L'amplitude de la rotation latérale de hanche est :",o:["20°", "45°", "35°", "60°"],a:3,e:"Rotation LATÉRALE hanche = 60°. Rotation MÉDIALE = 35°. Flexion = 120°. Extension = 20°. Abduction = 40°."},
  {c:"22",l:"Chap. 2.2",q:"Le TFL (tenseur du fascia lata) prend origine sur :",o:["L'épine iliaque antéro-inférieure (EIAI)", "Le grand trochanter", "L'épine iliaque antéro-supérieure (EIAS)", "La crête iliaque"],a:2,e:"TFL : EIAS → condyle lat. tibia via tractus ilio-tibial. Action : abduction + flexion hanche."},
  {c:"22",l:"Chap. 2.2",q:"Le labrum acétabulaire est composé de :",o:["Os spongieux", "Tissu conjonctif dense", "Fibrocartilage", "Cartilage hyalin"],a:2,e:"Labrum acétabulaire = FIBROCARTILAGE. Augmente la surface articulaire et la stabilité."},
  {c:"22",l:"Chap. 2.2",q:"Le ligament de la tête fémorale (ligament rond) avant la puberté a comme fonction principale :",o:["Assurer l'apport sanguin à la tête fémorale", "Maintenir la congruence articulaire", "Limiter l'adduction de hanche", "Stabiliser la tête fémorale"],a:0,e:"Avant puberté : lig. tête fémorale = apport VASCULAIRE à la tête fémorale. Adulte = stabilisateur secondaire."},
  {c:"22",l:"Chap. 2.2",q:"Les muscles réalisant la rotation médiale de hanche sont :",o:["Grand glutéal + carré fémoral + obturateurs", "Piriforme + jumeaux + obturateur ext.", "Moyen glutéal seul", "Fibres ant. petit + moyen glutéal + TFL"],a:3,e:"Rotation MÉDIALE : fibres ANT. petit glutéal + fibres ANT. moyen glutéal + TFL."},
  // CHAPITRE 2.3 extra
  {c:"23",l:"Chap. 2.3",q:"Le mécanisme de vissage (screw-home) du genou :",o:["Verrouille en extension par rotation lat. automatique tibia", "Verrouille en extension par rotation méd. automatique", "Déverrouille par le quadriceps", "Verrouille en flexion par rotation lat. automatique"],a:0,e:"Screw-home : extension terminale → rotation LATÉRALE automatique tibia → genou verrouillé. Déverrouillage = poplité (rotation méd.)."},
  {c:"23",l:"Chap. 2.3",q:"Le condyle fémoral médial, comparé au latéral, est :",o:["Plus large et plus long", "Plus étroit et plus long", "Plus large et plus court", "Plus étroit et plus court"],a:1,e:"Condyle MÉD. = plus ÉTROIT et plus LONG que le latéral."},
  {c:"23",l:"Chap. 2.3",q:"Le ménisque médial est plus souvent lésé car :",o:["Il adhère au LCM → moins mobile", "Il est plus convexe", "Il est plus petit", "Il est plus vascularisé"],a:0,e:"Ménisque méd. adhère au LCM → MOINS MOBILE → plus souvent lésé lors de valgus forcé (triade malheureuse)."},
  {c:"23",l:"Chap. 2.3",q:"L'hyperextension active du genou est de :",o:["5°", "15°", "0° (impossible)", "10°"],a:3,e:"Hyperextension ACTIVE = 10°. Hyperextension PASSIVE = 15°."},
  {c:"23",l:"Chap. 2.3",q:"Le plan profond (capsulaire) des ligaments antérieurs du genou comprend :",o:["Fascia lata + fascia jambier", "LCA + LCP", "Lig. patellaire + rétinaculum patellaire", "Lig. fémoro-patellaires + lig. ménisco-patellaires"],a:3,e:"Plan PROFOND ant. = lig. fémoro-patellaires (ailerons) + lig. ménisco-patellaires."},
  // CHAPITRE 2.5 extra
  {c:"25",l:"Chap. 2.5",q:"Le droit fémoral prend origine sur :",o:["Bord latéral ligne âpre + grand trochanter", "EIAS + face ant. corps fémoral", "Bord médial ligne âpre + ligne intertrochantérienne", "EIAI (tendon direct) + sillon supra-acétabulaire (tendon indirect)"],a:3,e:"Droit fémoral : tendon DIRECT = EIAI · tendon INDIRECT = sillon supra-acétabulaire. Seul chef biarticulaire."},
  {c:"25",l:"Chap. 2.5",q:"Le sartorius réalise sur la hanche :",o:["Flexion + adduction + rotation latérale", "Flexion + abduction + rotation latérale", "Extension + abduction + rotation latérale", "Flexion + adduction + rotation médiale"],a:1,e:"Sartorius : hanche = flexion + ABDUCTION + rotation LATÉRALE. 'Muscle du tailleur'."},
  {c:"25",l:"Chap. 2.5",q:"La patte d'oie PROFONDE correspond à :",o:["Semi-membraneux (3 tendons)", "Sartorius + Gracile + Semi-tendineux", "Gracile + Semi-tendineux + Semi-membraneux", "Sartorius + Semi-tendineux + Semi-membraneux"],a:0,e:"Patte d'oie PROFONDE = Semi-membraneux uniquement (3 tendons : direct + récurrent + réfléchi)."},
  {c:"25",l:"Chap. 2.5",q:"Le biceps fémoral réalise à la jambe :",o:["Flexion + rotation latérale", "Flexion uniquement", "Extension + rotation médiale", "Flexion + rotation médiale"],a:0,e:"Biceps fémoral : hanche = extension · jambe = flexion + rotation LATÉRALE. Seul ischio-jambier à faire la rotation lat."},
  {c:"25",l:"Chap. 2.5",q:"Le pectiné est innervé par :",o:["Nerf fémoral + parfois obturateur", "Nerf sciatique", "Nerf fémoral", "Nerf obturateur L2–L4"],a:2,e:"Pectiné = nerf FÉMORAL (exception dans la loge médiale). Les autres adducteurs = nerf obturateur."},
  // CHAPITRE 2.6 extra
  {c:"26",l:"Chap. 2.6",q:"Le tibial antérieur s'insère sur :",o:["Base 1er métatarsien uniquement", "Naviculaire + cunéiformes", "Face plantaire 1er cunéiforme + 1er métatarsien", "Tubercule 5e métatarsien"],a:2,e:"Tibial ant. : face lat. tibia → face plantaire 1er cunéiforme + 1er métatarsien. Flex. dorsale + adduction + supination."},
  {c:"26",l:"Chap. 2.6",q:"Le long fibulaire s'insère sur :",o:["Tubercule 5e métatarsien", "Base 1er métatarsien", "Base 5e métatarsien", "Naviculaire"],a:1,e:"Long fibulaire → BASE 1er métatarsien. Action : flex. plantaire + abduction + pronation."},
  {c:"26",l:"Chap. 2.6",q:"Le tibial postérieur réalise comme action principale :",o:["Flexion plantaire uniquement", "Flexion dorsale + abduction", "Éversion du pied", "Inversion du pied"],a:3,e:"Tibial post. = INVERSION du pied. Nerf tibial."},
  {c:"26",l:"Chap. 2.6",q:"Le gastrocnémien est BIARTICULAIRE car il agit sur :",o:["La hanche et la cheville", "La cheville et le pied", "Le genou et la cheville", "La hanche et le genou"],a:2,e:"Gastrocnémien : biarticulaire → flex. plantaire CHEVILLE + flexion GENOU. Soléaire = monoarticulaire."},
  {c:"26",l:"Chap. 2.6",q:"Le rétinaculum fléchisseur s'étend de :",o:["Calcanéum → naviculaire", "Tibia → fibula", "Malléole méd. → calcanéum", "Malléole lat. → calcanéum"],a:2,e:"Rétinaculum FLÉCHISSEUR : malléole MÉDIALE → calcanéum. Maintient tendons muscles profonds face méd. cheville."},
  // CHAPITRE 2.7 extra
  {c:"27",l:"Chap. 2.7",q:"Les lombricaux du pied prennent origine sur :",o:["Tendons LFO (bords médiaux)", "Face inférieure calcanéum", "Base des métatarsiens", "Cunéiformes et cuboïde"],a:0,e:"Lombricaux : tendons LFO (bords MÉDIAUX) → base phalanges proximales 2e–5e orteils."},
  {c:"27",l:"Chap. 2.7",q:"L'adducteur de l'hallux s'insère via :",o:["Directement sans sésamoïde", "Sésamoïde latéral", "Sésamoïde médial", "Les deux sésamoïdes"],a:1,e:"Adducteur hallux → sésamoïde LATÉRAL. Abducteur hallux → sésamoïde MÉDIAL."},
  {c:"27",l:"Chap. 2.7",q:"L'abducteur de l'hallux prend origine sur :",o:["Face inférieure calcanéum", "Tubercule médial de la tubérosité calcanéenne", "Bases 2e–5e métatarsiens", "Cunéiformes et structures plantaires"],a:1,e:"Abducteur hallux : tubercule MÉD. de la tubérosité calcanéenne → phalange proximale hallux via sésamoïde médial."},
  {c:"27",l:"Chap. 2.7",q:"Quelle est l'action de l'adducteur de l'hallux sur la voûte plantaire ?",o:["N'a aucun rôle sur la voûte", "Soutient uniquement la voûte longitudinale", "Soutient uniquement la voûte transversale", "Soutient la voûte longitudinale ET transversale"],a:3,e:"Adducteur hallux = soutient voûte LONGITUDINALE ET TRANSVERSALE."},
  {c:"27",l:"Chap. 2.7",q:"Le carré plantaire s'insère sur :",o:["Face plantaire naviculaire", "Base phalanges proximales", "Bord latéral du tendon LFO", "Tubercule médial calcanéum"],a:2,e:"Carré plantaire : face inf. calcanéum → bord LATÉRAL tendon LFO. Nerf plantaire latéral."},
  // CHAPITRE 2.8 extra
  {c:"28",l:"Chap. 2.8",q:"Le nerf fémoral pénètre dans la cuisse :",o:["Médialement aux vaisseaux fémoraux", "En avant du lig. inguinal", "Entre les vaisseaux fémoraux", "Latéralement aux vaisseaux fémoraux"],a:3,e:"Nerf fémoral : passe derrière le lig. inguinal + LATÉRALEMENT aux vaisseaux fémoraux (VAN : Veine + Artère + Nerf, de méd. à lat.)."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf sciatique innerve en branches directes :",o:["Grand glutéal + piriforme", "Chef long biceps + semi-tendineux + semi-membraneux + grand add. faisceau chond.", "Quadriceps + sartorius", "Adducteurs + gracile"],a:1,e:"Sciatique direct : chef LONG biceps + semi-tendineux + semi-membraneux + grand add. faisceau CHONDYLIEN."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf tibial innerve la zone :",o:["Médiale de la jambe", "Latérale de la jambe", "Antérieure de la jambe", "Postérieure de la jambe"],a:3,e:"Nerf TIBIAL = zone POSTÉRIEURE jambe (triceps sural + poplité + tibial post. + long fléch. orteils + hallux + plantaire)."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf plantaire latéral innerve en sensitif :",o:["3 orteils et demi médiaux", "Toute la plante du pied", "2 orteils latéraux uniquement", "5e orteil + moitié lat. 4e orteil"],a:3,e:"N. plantaire LATÉRAL sensitif : 5e orteil + moitié lat. 4e orteil."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf génito-fémoral est issu de :",o:["L1 uniquement", "L3–L4", "L2–L3", "L1–L2"],a:3,e:"N. génito-fémoral = L1–L2. Innerve le crémaster (moteur) + sensitif région inguinale."}
];
 
// SÉRIE 3 — 80 questions supplémentaires
var EXTRA_Q2 = [
  // CHAP 1
  {c:"1",l:"Chap. 1",q:"Le disque intervertébral est composé de :",o:["Anneau fibreux au centre + nucleus pulposus en périphérie", "Uniquement de cartilage hyalin", "Uniquement de fibrocartilage", "Nucleus pulposus au centre + anneau fibreux en périphérie"],a:3,e:"Disque intervertébral : NUCLEUS PULPOSUS (gélatineux) au centre + ANNEAU FIBREUX (fibrocartilage) en périphérie."},
  {c:"1",l:"Chap. 1",q:"L'articulation atlanto-occipitale permet principalement :",o:["L'inclinaison uniquement", "La flexion/extension de la tête (oui/oui)", "La rotation et l'inclinaison", "La rotation de la tête"],a:1,e:"Atlanto-occipitale (C0–C1) = articulation condylienne → FLEXION/EXTENSION + légère inclinaison ('dire oui'). La rotation = atlanto-axiale (C1–C2)."},
  {c:"1",l:"Chap. 1",q:"Le ligament jaune relie :",o:["Les processus épineux", "Les corps vertébraux", "Les lames vertébrales adjacentes", "Les processus transverses"],a:2,e:"Ligament JAUNE = entre les LAMES vertébrales adjacentes. Riche en fibres élastiques (jaune). Limite la flexion."},
  {c:"1",l:"Chap. 1",q:"La hernie discale la plus fréquente touche le niveau :",o:["C5–C6", "T12–L1", "L4–L5 et L5–S1", "T10–T11"],a:2,e:"Hernies discales les plus fréquentes = L4–L5 et L5–S1 car ce sont les niveaux les plus sollicités mécaniquement."},
  {c:"1",l:"Chap. 1",q:"Le ligament nucal est :",o:["Le ligament longitudinal antérieur cervical", "Un ligament transversaire cervical", "Un ligament inter-épineux cervical élargi", "Le ligament longitudinal postérieur cervical"],a:2,e:"Ligament nucal = ligament inter-épineux CERVICAL élargi. S'étend de la protubérance occipitale à C7."},
  // CHAP 2
  {c:"2",l:"Chap. 2",q:"Le ptérion est :",o:["Un foramen de la base du crâne", "La jonction de 4 os : temporal, pariétal, frontal, sphénoïde", "La jonction des sutures sagittale et lambdoïde", "La jonction des sutures coronale et sagittale"],a:1,e:"PTÉRION = jonction de 4 os : temporal + pariétal + frontal + sphénoïde. Zone fragile car l'artère méningée moyenne passe dessous."},
  {c:"2",l:"Chap. 2",q:"L'os temporal présente :",o:["La fosse ptérygoïdienne", "Le tubercule adducteur", "La surface semi-lunaire", "La fosse mandibulaire (glène temporale)"],a:3,e:"Os temporal présente la FOSSE MANDIBULAIRE (glène temporale) qui s'articule avec le condyle mandibulaire = ATM."},
  {c:"2",l:"Chap. 2",q:"La lame criblée de l'ethmoïde laisse passer :",o:["Le nerf optique", "Le nerf olfactif (I)", "Le nerf trijumeau", "L'artère carotide interne"],a:1,e:"Lame criblée de l'ethmoïde = passage du nerf OLFACTIF (I). Nombreuses perforations pour les filets olfactifs."},
  // CHAP 3
  {c:"3",l:"Chap. 3",q:"Le dentelé postérieur supérieur prend origine sur :",o:["Épi. T11–L3", "Lig. nucal inf. + épi. C7–T3", "Épi. T6–T10", "Apoph. transv. C7–T3"],a:1,e:"Dentelé post. SUP. : lig. nucal inf. + épi. C7–T3 → bord inf. côtes II–V. Action INSPIRATOIRE."},
  {c:"3",l:"Chap. 3",q:"Le grand dorsal réalise sur l'humérus :",o:["Flexion + abduction + rotation latérale", "Extension + adduction + rotation médiale", "Flexion + adduction + rotation latérale", "Extension + abduction + rotation médiale"],a:1,e:"Grand dorsal sur humérus : EXTENSION + ADDUCTION + rotation MÉDIALE."},
  {c:"3",l:"Chap. 3",q:"L'élévateur de la scapula s'insère sur :",o:["Épine de la scapula", "Acromion", "Angle inférieur de la scapula", "Bord médial supérieur de la scapula"],a:3,e:"Élévateur scapula : apoph. transv. C1–C4 → bord MÉDIAL SUPÉRIEUR de la scapula."},
  {c:"3",l:"Chap. 3",q:"Les rhomboïdes sont innervés par :",o:["Plexus cervical C3–C4", "Nerf dorsal de la scapula C4–C5", "Nerf thoracodorsal C6–C8", "Nerf accessoire XI"],a:1,e:"Rhomboïdes = nerf dorsal de la SCAPULA C4–C5. Même innervation que l'élévateur de la scapula."},
  // CHAP 4
  {c:"4",l:"Chap. 4",q:"Le plexus cervical est formé par :",o:["Branches ant. C1–C5", "Branches ant. C2–C5", "Branches ant. C1–C4", "Branches post. C1–C4"],a:2,e:"Plexus cervical = branches antérieures de C1 à C4. Donne le nerf phrénique (C3–C5), les nerfs cutanés du cou."},
  {c:"4",l:"Chap. 4",q:"L'anse cervicale innerve :",o:["Tous les muscles infra-hyoïdiens", "Les muscles supra-hyoïdiens", "Le trapèze et le SCM", "Les muscles infra-hyoïdiens (sauf thyrohyoïdien)"],a:3,e:"Anse cervicale (C1–C3) innerve les muscles INFRA-HYOÏDIENS sauf le thyrohyoïdien (anse + XII)."},
  {c:"4",l:"Chap. 4",q:"Le sternohyoïdien prend origine sur :",o:["La face postérieure du sternum", "Le sternum et la clavicule", "La cartilage thyroïde", "L'apophyse xiphoïde"],a:1,e:"Sternohyoïdien : sternum + clavicule → hyoïde. Il abaisse l'hyoïde."},
  // CHAP 5
  {c:"5",l:"Chap. 5",q:"Le ptérygoïdien latéral prend origine sur :",o:["Arcade zygomatique + fosse temporale", "Grande aile sphénoïde + face lat. lame lat. apoph. ptérygoïde", "Plancher fosse temporale", "Fosse ptérygoïdienne entre les 2 lames"],a:1,e:"Ptérygoïdien LATÉRAL : grande aile sphénoïde + face lat. lame LAT. apoph. ptérygoïde → col mandibule + disque."},
  {c:"5",l:"Chap. 5",q:"Lors de l'élévation mandibulaire (fermeture bouche) :",o:["Le disque reste fixe et le condyle monte", "Le condyle avance seul", "Les ptérygoïdiens latéraux sont actifs", "Le condyle et le disque reculent puis le condyle tourne"],a:3,e:"Élévation : condyle + disque RECULENT d'abord puis le condyle TOURNE sur la face inf. du ménisque. Muscles : temporal + masséter + ptéryg. méd."},
  {c:"5",l:"Chap. 5",q:"Le masséter et le ptérygoïdien médial forment ensemble :",o:["Une écharpe musculaire autour de l'angle mandibulaire", "La fosse infra-temporale", "Le triangle interptérygoïdien", "Le raphé ptérygomandibulaire"],a:0,e:"Masséter (face lat.) + ptérygoïdien médial (face méd.) = écharpe musculaire autour de l'ANGLE MANDIBULAIRE."},
  // THÈME 6
  {c:"6",l:"Thème 6",q:"Le hiatus aortique (T12) contient :",o:["Aorte + canal thoracique + veine azygos", "Aorte + veine cave inférieure", "Aorte uniquement", "Aorte + nerfs vagues"],a:0,e:"T12 = aorte + CANAL THORACIQUE + veine AZYGOS. T10 = œsophage + nerfs vagues. T8 = veine cave."},
  {c:"6",l:"Thème 6",q:"Le diaphragme s'abaisse lors de :",o:["La toux uniquement", "L'expiration", "Le hoquet", "L'inspiration"],a:3,e:"Diaphragme s'ABAISSE à l'INSPIRATION (augmente volume thoracique). S'élève à l'expiration."},
  {c:"6",l:"Thème 6",q:"L'insertion sternale du diaphragme se fait sur :",o:["Manubrium sternal", "Apophyse xiphoïde", "Corps du sternum", "1ère côte + manubrium"],a:1,e:"Insertion STERNALE diaphragme = apophyse XIPHOÏDE."},
  {c:"6",l:"Thème 6",q:"Les intercostaux externes s'étendent :",o:["De l'angle costal au sternum", "De l'angle costal à 5–6 cm du sternum", "De la tête costale à l'angle costal", "Du tubercule costal aux cartilages costaux"],a:3,e:"Intercostaux EXTERNES : tubercule costal → cartilages costaux. Au-delà = membrane intercostale externe."},
  // CHAP 7
  {c:"7",l:"Chap. 7",q:"Le feuillet antérieur de la gaine du droit au-dessus de l'EIAS est formé par :",o:["½ oblique int. + transverse", "Oblique ext. + ½ oblique int.", "Les 3 aponévroses ensemble", "Transverse + oblique ext."],a:1,e:"Feuillet ANT. au-dessus EIAS = oblique ext. + ½ oblique int. Feuillet POST. = ½ oblique int. + transverse."},
  {c:"7",l:"Chap. 7",q:"En dessous de l'EIAS, les 3 aponévroses forment :",o:["Uniquement la paroi antérieure", "La gaine complète du droit", "Uniquement la paroi postérieure", "Les deux parois ant. et post."],a:0,e:"En dessous EIAS = les 3 aponévroses passent toutes en AVANT → uniquement paroi ANTÉRIEURE. Plus de paroi post."},
  {c:"7",l:"Chap. 7",q:"Quelles hernies peuvent se produire dans la ligne blanche ?",o:["Hernie ombilicale et épigastrique", "Hernie hiatale et fémorale", "Hernie sciatique et obturatrice", "Hernie inguinale et crurale"],a:0,e:"Ligne blanche : hernies OMBILICALE et ÉPIGASTRIQUE. Hernies inguinales = canal inguinal."},
  {c:"7",l:"Chap. 7",q:"La paroi latérale du canal des adducteurs (de Hunter) est formée par :",o:["Le sartorius", "Le grand adducteur", "Le long adducteur", "Le vaste médial"],a:3,e:"Canal Hunter : paroi ant.-int. = sartorius · paroi post. = long add. + grand add. · paroi LAT. = VASTE MÉDIAL."},
  // CHAP 8
  {c:"8",l:"Chap. 8",q:"Le fascia viscéral pelvien entoure :",o:["Les muscles du plancher", "Le péritoine pariétal", "Les parois pelviennes", "Les organes pelviens (= fascia endopelvien)"],a:3,e:"Fascia VISCÉRAL = entoure les organes pelviens (= fascia endopelvien). Fascia PARIÉTAL = tapisse les parois."},
  {c:"8",l:"Chap. 8",q:"L'action principale de l'élévateur de l'anus chez la femme est :",o:["Soutenir viscères + élever plancher + sphincter vaginal", "Uniquement maintenir l'angle recto-anal", "Uniquement renforcer sphincter anal", "Uniquement soutenir les viscères"],a:0,e:"Élévateur anus ♀ : soutient viscères + élève plancher + maintient angle recto-anal + renforce sphincter anal + SPHINCTER VAGINAL."},
  {c:"8",l:"Chap. 8",q:"Le transverse superficiel du périnée stabilise :",o:["Le corps périnéal", "La membrane périnéale", "La base du clitoris", "Le fascia obturateur"],a:0,e:"Transverse superficiel : tubérosité ischiatique → corps périnéal. Stabilise le CORPS PÉRINÉAL."},
  {c:"8",l:"Chap. 8",q:"Le nerf pudendal passe dans le canal :",o:["Obturateur", "De Hunter", "D'Alcock", "Inguinal"],a:2,e:"Nerf pudendal passe dans le canal D'ALCOCK (canal pudendal) après être entré par le petit foramen sciatique."},
  // CHAP 9
  {c:"9",l:"Chap. 9",q:"Le LCR est produit par :",o:["Les méninges", "Les plexus choroïdes des ventricules", "Les cellules gliales", "L'épendyme uniquement"],a:1,e:"Le LCR est produit par les PLEXUS CHOROÏDES dans les ventricules cérébraux."},
  {c:"9",l:"Chap. 9",q:"La dure-mère spinale forme les :",o:["Gaines des nerfs rachidiens jusqu'au foramen intervertébral", "Arachnoïdes", "Plexus choroïdes", "Pie-mères"],a:0,e:"La dure-mère spinale forme les GAINES des nerfs rachidiens jusqu'au foramen intervertébral."},
  {c:"9",l:"Chap. 9",q:"Combien y a-t-il de paires de nerfs lombaires ?",o:["5", "6", "3", "4"],a:0,e:"5 paires de nerfs lombaires (L1–L5). 8 cervicaux, 12 thoraciques, 5 lombaires, 5 sacrés, 1 coccygien."},
  {c:"9",l:"Chap. 9",q:"Le nerf XII (hypoglosse) innerve :",o:["Les muscles masticateurs", "Le trapèze + SCM", "Les muscles mimique", "Les muscles de la langue + thyrohyoïdien + géniohyoïdien"],a:3,e:"NC XII = muscles de la LANGUE + thyrohyoïdien + géniohyoïdien. NC XI = trapèze + SCM."},
  {c:"9",l:"Chap. 9",q:"Le nerf V (trijumeau) réalise :",o:["Moteur muscles langue", "Moteur trapèze + SCM", "Moteur muscles mimique + sensitif face", "Sensitif face + moteur muscles masticateurs"],a:3,e:"NC V = trijumeau : SENSITIF face + MOTEUR muscles masticateurs (branche mandibulaire V3)."},
  // CHAP 2.2
  {c:"22",l:"Chap. 2.2",q:"L'amplitude de l'abduction de hanche est de :",o:["40°", "50°", "20°", "30°"],a:0,e:"Abduction hanche = 40°. Adduction = 30°. Mnémotechnique : Abd > Add (40 > 30)."},
  {c:"22",l:"Chap. 2.2",q:"Le grand glutéal s'insère via ses fibres SUPERFICIELLES sur :",o:["La crête du grand glutéal (ligne âpre)", "Le petit trochanter", "Le tractus ilio-tibial", "La tubérosité glutéale"],a:2,e:"Grand glutéal : fibres SUPERFICIELLES → tractus ILIO-TIBIAL. Fibres PROFONDES → crête du grand glutéal."},
  {c:"22",l:"Chap. 2.2",q:"Le moyen glutéal est innervé par :",o:["Nerf glutéal supérieur", "Nerf obturateur", "Nerf glutéal inférieur", "Nerf sciatique"],a:0,e:"Moyen glutéal = nerf glutéal SUPÉRIEUR (comme petit glutéal + TFL). Grand glutéal = nerf glutéal INFÉRIEUR."},
  {c:"22",l:"Chap. 2.2",q:"Le carré fémoral s'insère sur :",o:["Le grand trochanter", "La fosse trochantérique", "Le petit trochanter", "La crête intertrochantérienne"],a:3,e:"Carré fémoral : tubérosité ischiatique → CRÊTE INTERtrochantérienne. Action : rotation lat. + adduction."},
  {c:"22",l:"Chap. 2.2",q:"Les jumeaux supérieur et inférieur ont des origines différentes. Le jumeau supérieur origine sur :",o:["L'épine ischiatique", "Le sacrum", "La tubérosité ischiatique", "La membrane obturatrice"],a:0,e:"Jumeau SUP : ÉPINE ischiatique. Jumeau INF : TUBÉROSITÉ ischiatique. Les deux → face int. grand trochanter."},
  // CHAP 2.3
  {c:"23",l:"Chap. 2.3",q:"La patte d'oie superficielle est constituée de :",o:["Semi-tendineux + semi-membraneux + gracile", "Sartorius + biceps fémoral + gracile", "Sartorius + gracile + poplité", "Sartorius + gracile + semi-tendineux"],a:3,e:"Patte d'oie SUPERFICIELLE = Sartorius + Gracile + Semi-tendineux. Insertion sur la face méd. tibia proximal."},
  {c:"23",l:"Chap. 2.3",q:"Le tendon du poplité est :",o:["Intra-capsulaire et sort par un trou dans la capsule", "Extra-capsulaire et intra-synovial", "Extra-capsulaire et extra-synovial", "Intra-capsulaire et intra-synovial"],a:0,e:"Poplité : tendon INTRA-capsulaire qui sort par un TROU dans la partie postérieure de la capsule."},
  {c:"23",l:"Chap. 2.3",q:"Quel mouvement du genou est réalisé par le biceps fémoral uniquement ?",o:["Rotation latérale du genou", "Flexion du genou", "Extension du genou", "Rotation médiale du genou"],a:0,e:"BICEPS FÉMORAL = seul ischio-jambier qui fait la ROTATION LATÉRALE du genou."},
  {c:"23",l:"Chap. 2.3",q:"Le ménisque latéral est en forme de :",o:["O (presque circulaire)", "V", "L", "C"],a:0,e:"Ménisque LATÉRAL = forme de O (presque circulaire). Ménisque MÉDIAL = forme de C (plus grand, moins mobile)."},
  {c:"23",l:"Chap. 2.3",q:"Le ligament poplité ARQUÉ renforce :",o:["La capsule antérieure", "La capsule postérieure et limite l'hyperextension", "La capsule latérale", "Le LCA"],a:1,e:"Lig. poplité ARQUÉ : renforce capsule POST. + limite hyperextension. Lig. poplité OBLIQUE = aussi capsule post."},
  // CHAP 2.5
  {c:"25",l:"Chap. 2.5",q:"Le vaste intermédiaire prend origine sur :",o:["Faces antérieure et latérale du corps fémoral", "Bord latéral ligne âpre + grand trochanter", "Bord médial ligne âpre fémur", "Ligne intertrochantérienne + grand trochanter"],a:0,e:"Vaste intermédiaire : faces ANT. et LAT. du corps fémoral. Vaste lat. = bord lat. ligne âpre. Vaste méd. = bord méd."},
  {c:"25",l:"Chap. 2.5",q:"Le tendon récurrent du semi-membraneux forme :",o:["La patte d'oie superficielle", "Le ligament collatéral médial", "Le rétinaculum médial patella", "Le ligament poplité oblique"],a:3,e:"Semi-membraneux : tendon RÉCURRENT → ligament POPLITÉ OBLIQUE. Tendon direct → partie post. condyle méd. tibia."},
  {c:"25",l:"Chap. 2.5",q:"Le gracile réalise sur la jambe :",o:["Extension + rotation latérale", "Flexion + rotation médiale", "Extension + rotation médiale", "Flexion + rotation latérale"],a:1,e:"Gracile : hanche = adduction · jambe = FLEXION + rotation MÉDIALE. Patte d'oie superficielle."},
  {c:"25",l:"Chap. 2.5",q:"L'obturateur externe est innervé par :",o:["Nerf obturateur L2–L4 (plexus lombaire)", "Branches du plexus sacré", "Nerf obturateur interne L5–S1", "Nerf fémoral"],a:0,e:"Obturateur EXTERNE = nerf obturateur L2–L4 (PLEXUS LOMBAIRE). Obturateur INTERNE = L5–S1 (plexus sacré)."},
  {c:"25",l:"Chap. 2.5",q:"Le court adducteur et le long adducteur ont en commun :",o:["Même origine sur branche ischiopubienne", "Même innervation par le nerf fémoral", "Adduction + flexion + rotation externe cuisse", "Insertion sur le tubercule adducteur"],a:2,e:"Court ET long adducteur : adduction + flexion + rotation EXTERNE cuisse. Innervation = nerf obturateur pour les deux."},
  // CHAP 2.6
  {c:"26",l:"Chap. 2.6",q:"Le long extenseur des orteils réalise sur le pied :",o:["Flex. dorsale + abduction + pronation", "Extension + inversion", "Flex. dorsale + adduction + supination", "Flex. plantaire + abduction"],a:0,e:"Long ext. orteils : extension orteils + flex. dorsale + ABDUCTION + PRONATION. (tibial ant. = adduction + supination)."},
  {c:"26",l:"Chap. 2.6",q:"Le 3e fibulaire est :",o:["Un muscle de la loge postérieure", "Toujours présent et bien développé", "Le même muscle que le court fibulaire", "Muscle inconstant souvent fusionné avec le long ext. orteils"],a:3,e:"3e fibulaire = INCONSTANT, souvent fusionné avec le long ext. orteils. Face int. fibula → base 5e métatarsien."},
  {c:"26",l:"Chap. 2.6",q:"Le plantaire prend origine sur :",o:["Face post. tibia", "Condyle méd. fémur", "Tête fibulaire", "Condyle lat. fémur (profond/gastrocnémien)"],a:3,e:"Plantaire : condyle LAT. fémur (profond par rapport au gastrocnémien) → bord méd. tendon d'Achille."},
  {c:"26",l:"Chap. 2.6",q:"L'articulation talocalcanéo-naviculaire (Chopart médiale) a comme surface articulaire :",o:["Uniquement tête du talus + naviculaire", "Talus + cuboïde + naviculaire", "Calcanéum + cuboïde uniquement", "Tête du talus + naviculaire + face ant. calcanéum + lig. Spring"],a:3,e:"Talocalcanéo-naviculaire : tête du talus + face post. naviculaire + face ant. sup. calcanéum + lig. de SPRING."},
  {c:"26",l:"Chap. 2.6",q:"Le long fléchisseur de l'hallux prend origine sur :",o:["Condyle lat. tibia + fibula", "Membrane interosseuse", "Face post. tibia 1/3 moyen", "Fibula 1/2 distal"],a:3,e:"Long fléchisseur hallux : FIBULA (1/2 distal) → base phalange distale hallux. Flex. hallux + inversion."},
  // CHAP 2.7
  {c:"27",l:"Chap. 2.7",q:"Le court fléchisseur de l'hallux est innervé par :",o:["Nerfs plantaires médial ET latéral", "Nerf fibulaire profond", "Nerf plantaire latéral uniquement", "Nerf plantaire médial uniquement"],a:0,e:"Court fléch. hallux = nerfs plantaires MÉDIAL ET LATÉRAL (innervation mixte). S'insère via les sésamoïdes."},
  {c:"27",l:"Chap. 2.7",q:"L'aponévrose plantaire s'attache postérieurement sur :",o:["Le naviculaire", "Le 1er métatarsien", "Le talus", "Le calcanéum"],a:3,e:"Aponévrose plantaire : s'attache au CALCANÉUM en postérieur → se divise en 5 fascicules vers les orteils."},
  {c:"27",l:"Chap. 2.7",q:"Le court extenseur des orteils (pédieux) est divisé en :",o:["3 fascicules", "2 fascicules", "5 fascicules", "4 fascicules"],a:0,e:"Court ext. orteils = 3 FASCICULES → tendons du long ext. orteils (2e, 3e, 4e orteils). Nerf fibulaire profond."},
  {c:"27",l:"Chap. 2.7",q:"Le fléchisseur du 5e orteil prend origine sur :",o:["Face inférieure calcanéum", "Base 5e métatarsien + long lig. plantaire", "Moitié distale 5e métatarsien", "Tubercule 5e métatarsien"],a:1,e:"Fléchisseur 5e : BASE 5e métatarsien + long ligament plantaire → base 1ère phalange 5e orteil."},
  {c:"27",l:"Chap. 2.7",q:"L'abducteur du 5e orteil prend origine sur :",o:["Base 5e métatarsien", "Face inférieure calcanéum", "Tubercule 5e métatarsien", "Long ligament plantaire"],a:1,e:"Abducteur 5e : face INF. calcanéum → face lat. 1ère phalange 5e orteil. Action : flexion + ABDUCTION."},
  // CHAP 2.8
  {c:"28",l:"Chap. 2.8",q:"Le nerf obturateur innerve en moteur :",o:["Ischio-jambiers + grand adducteur", "Grand glutéal + moyen glutéal", "Gracile + adducteurs + obturateur ext.", "Quadriceps + sartorius + pectiné"],a:2,e:"Nerf obturateur : gracile + long add. + court add. + grand add. (faisceau add.) + obturateur ext. + sensitif face int. cuisse."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf fibulaire superficiel innerve en moteur :",o:["Zone antérieure jambe", "Interosseux du pied", "Long + court fibulaire", "Tibial antérieur uniquement"],a:2,e:"Fibulaire SUPERFICIEL : long fibulaire + court fibulaire. Sensitif : face dorsale pied."},
  {c:"28",l:"Chap. 2.8",q:"Le plexus sacré est formé par :",o:["Branches ant. S1–S5", "Branches ant. L5–S4", "Tronc lombo-sacré + branches ant. S1–S3", "Branches ant. L1–L4"],a:2,e:"Plexus sacré = TRONC LOMBO-SACRÉ (L4–L5) + branches ant. S1–S3."},
  {c:"28",l:"Chap. 2.8",q:"Dans la jambe, la zone antérieure est innervée par :",o:["Nerf fibulaire profond", "Nerf tibial", "Nerf fibulaire superficiel", "Nerf saphène"],a:0,e:"Zone ANT. jambe = nerf FIBULAIRE PROFOND (tibial ant. + long ext. orteils + long ext. hallux + 3e fibulaire)."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf fémoral est la branche la plus importante du plexus lombaire ?",o:["Vrai","Faux"],a:0,e:"VRAI. Le nerf FÉMORAL est la branche la PLUS IMPORTANTE du plexus lombaire (L2–L4)."}
];
 
var EXTRA_Q3 = [
  // SERIE 4 - ARTHROLOGIE + O/I/N/F + COUCHES + LIMITES
  // CHAP 1 - ARTHROLOGIE COLONNE
  {c:"1",l:"Chap. 1",q:"Les articulations uncovertébrales (de Luschka) se trouvent au niveau :",o:["Lombaire uniquement", "Sacré", "Thoracique uniquement", "Cervical C3–C7"],a:3,e:"Articulations de Luschka = CERVICALES C3–C7. Se forment entre les processus unciformes des corps vertébraux cervicaux."},
  {c:"1",l:"Chap. 1",q:"Le ligament longitudinal postérieur limite :",o:["L'extension de la colonne", "La flexion de la colonne", "La rotation de la colonne", "L'inclinaison de la colonne"],a:1,e:"Lig. longitudinal POSTÉRIEUR : limite la FLEXION (se tend en flexion). Lig. ant. : limite l'extension."},
  {c:"1",l:"Chap. 1",q:"Les articulations costovertébrales sont de type :",o:["Arthrodie (plane)", "Condylienne", "Énarthrose", "Trochléenne"],a:0,e:"Articulations costovertébrales = ARTHRODIES (planes). Permettent de petits glissements lors des mouvements respiratoires."},
  // CHAP 2 - TYPE ARTICULATION
  {c:"2",l:"Chap. 2",q:"L'articulation temporo-mandibulaire est de type :",o:["Condylienne simple", "Énarthrose", "Trochoïde", "Ginglymo-arthrodiale (bicondylaire modifiée)"],a:3,e:"ATM = ginglymo-arthrodiale : CHARNIÈRE (ginglyme) + GLISSEMENT (arthrodiale). 2 degrés de liberté."},
  // CHAP 3 - MUSCLES O/I/N/F
  {c:"3",l:"Chap. 3",q:"L'insertion du trapèze se fait sur :",o:["1/3 lat. clavicule + acromion + épine scapula", "Bord méd. scapula uniquement", "Apoph. épineuses C1–T12", "Apoph. transv. C1–C4"],a:0,e:"Trapèze I : 1/3 LAT. clavicule + ACROMION + ÉPINE scapula. O : ligne nucale sup. + prot. occi. ext. + lig. nucal + épi. C7–T12."},
  {c:"3",l:"Chap. 3",q:"Le grand dorsal est innervé par :",o:["Nerf subscapulaire", "Nerf accessoire XI", "Nerf dorsal scapula C4–C5", "Nerf thoracodorsal C6–C8"],a:3,e:"Grand dorsal = nerf THORACODORSAL C6–C8."},
  {c:"3",l:"Chap. 3",q:"L'action du trapèze : les fibres supérieures font :",o:["Abductent la scapula", "Abaissent la scapula", "Rétractent la scapula", "Élèvent la scapula + rotation"],a:3,e:"Fibres SUP. trapèze : ÉLÈVENT la scapula + rotation scapulaire. Fibres moy. : adduction. Fibres inf. : abaissement."},
  {c:"3",l:"Chap. 3",q:"Le petit droit postérieur de la tête fait :",o:["Extension tête UNIQUEMENT", "Rotation homolatérale uniquement", "Extension + rotation homolatérale", "Inclinaison + extension"],a:0,e:"Petit droit post. : tubercule post. atlas → occipital partie méd. Action : EXTENSION tête UNIQUEMENT (pas de rotation)."},
  // CHAP 4 - MUSCLES COUCHES O/I/N/F
  {c:"4",l:"Chap. 4",q:"Les muscles infra-hyoïdiens sont organisés en :",o:["3 plans (sup., moy., prof.)", "4 plans", "2 plans (superficiel et profond)", "Un seul plan"],a:2,e:"Muscles infra-hyoïdiens = 2 plans : SUPERFICIEL (sterno-hyoïdien + omo-hyoïdien) + PROFOND (sterno-thyroïdien + thyro-hyoïdien)."},
  {c:"4",l:"Chap. 4",q:"Le scalène antérieur prend origine sur :",o:["Apoph. transv. C2–C7", "Apoph. transv. C3–C6", "Apoph. transv. C1–C4", "Apoph. transv. C4–C6"],a:1,e:"Scalène ANTÉRIEUR : apoph. transv. C3–C6 → 1ère côte. Moyen : C2–C7. Postérieur : C4–C6."},
  {c:"4",l:"Chap. 4",q:"L'action bilatérale du long du cou est :",o:["Extension cervicale", "Inclinaison bilatérale", "Rotation homolatérale", "Flexion cervicale"],a:3,e:"Long du cou BILATÉRAL = FLEXION cervicale. Unilatéral = inclinaison + rotation controlatérale."},
  {c:"4",l:"Chap. 4",q:"Le droit antérieur de la tête s'insère sur :",o:["La ligne nucale supérieure", "La partie basilaire de l'os occipital", "L'apophyse transverse de C1", "L'apophyse épineuse de C2"],a:1,e:"Droit ant. tête : masse latérale atlas (C1) → partie BASILAIRE occipital. Action : flexion tête sur atlas."},
  // CHAP 5 - ARTHROLOGIE ATM + MUSCLES
  {c:"5",l:"Chap. 5",q:"Quelle structure forme le plancher de la fosse mandibulaire dans l'ATM ?",o:["Le ligament calcanéo-naviculaire Spring", "La tête de la mandibule", "La tête du talus", "Le ligament temporo-mandibulaire"],a:1,e:"Le plancher de la fosse mandibulaire = TÊTE DE LA MANDIBULE (condyle). La fosse = creux du temporal."},
  {c:"5",l:"Chap. 5",q:"Le temporal s'insère sur :",o:["Col mandibule + disque", "Fosse ptérygoïdienne", "Face latérale branche mandibule", "Apophyse coronoïde de la mandibule"],a:3,e:"Temporal : plancher fosse temporale → APOPHYSE CORONOÏDE mandibule. Élève + rétracte (fibres post.)."},
  {c:"5",l:"Chap. 5",q:"Les muscles masticateurs sont au nombre de :",o:["3", "4", "5", "6"],a:1,e:"4 muscles masticateurs : temporal + masséter + ptérygoïdien LATÉRAL + ptérygoïdien MÉDIAL. Tous innervés par V3."},
  {c:"5",l:"Chap. 5",q:"La propulsion mandibulaire est limitée par :",o:["Le masséter", "Les fibres postérieures du temporal", "Le lig. sphéno-mand.", "Le lig. temporo-mand. lat."],a:3,e:"Lig. temporo-mand. LAT. = limite les mvt vers l'ARRIÈRE (rétropulsion). La propulsion est limitée par les ligaments postérieurs de la capsule."},
  // THÈME 6 - COUCHES INTERCOSTAUX
  {c:"6",l:"Thème 6",q:"Les intercostaux intimes s'étendent :",o:["De l'angle costal à 5–6 cm du sternum", "De l'angle costal au sternum", "Du tubercule costal aux cartilages costaux", "De la tête costale à l'angle costal"],a:0,e:"Intercostaux INTIMES : angle costal → 5–6 cm du sternum. Entre internes et intimes = faisceau neurovasculaire."},
  {c:"6",l:"Thème 6",q:"Les 3 couches de muscles intercostaux de la plus superficielle à la plus profonde sont :",o:["Internes → externes → intimes", "Intimes → internes → externes", "Externes → internes → intimes", "Internes → intimes → externes"],a:2,e:"De superficiel à profond : EXTERNES → INTERNES → INTIMES. Le faisceau neurovasculaire passe entre internes et intimes."},
  {c:"6",l:"Thème 6",q:"Le dentelé postérieur supérieur agit lors de :",o:["L'expiration forcée", "La stabilisation du thorax", "L'inspiration (élève côtes II–V)", "L'expiration au repos"],a:2,e:"Dentelé post. SUP. = INSPIRATEUR : élève côtes II–V. Action accessoire à l'inspiration."},
  // CHAP 7 - COUCHES PAROI ABDOMINALE
  {c:"7",l:"Chap. 7",q:"De la superficie à la profondeur, l'ordre des couches de la paroi abdominale est :",o:["Oblique int. → oblique ext. → transverse → péritoine", "Oblique ext. → transverse → oblique int. → fascia → péritoine", "Péritoine → fascia → transverse → oblique int. → oblique ext.", "Oblique ext. → oblique int. ant. → oblique int. post. → transverse → fascia transversalis → péritoine"],a:3,e:"Superficiel → profond : oblique ext. → oblique int. ant. → oblique int. post. → transverse → fascia transversalis → PÉRITOINE."},
  {c:"7",l:"Chap. 7",q:"La loge postérieure de l'abdomen contient :",o:["Le transverse uniquement", "Le carré des lombes et le psoas", "Le droit de l'abdomen", "Les obliques"],a:1,e:"Loge POST. abdomen = carré des lombes + psoas (grand psoas). Le psoas est classé ici mais agit surtout sur la hanche."},
  {c:"7",l:"Chap. 7",q:"Le triangle fémoral de Scarpa a comme plancher :",o:["Le pectiné et le long adducteur", "Le grand adducteur et le couturier", "L'iliopsoas et le pectiné", "Le droit fémoral et le couturier"],a:2,e:"Plancher triangle de Scarpa = ILIOPSOAS + PECTINÉ. Limites : lig. inguinal (sup.) + sartorius (lat.) + long adducteur (méd.)."},
  // CHAP 8 - COUCHES PÉRINÉE
  {c:"8",l:"Chap. 8",q:"Le diaphragme pelvien est composé de :",o:["Ischiocaverneux + bulbo-spongieux", "Transverse profond + sphincter urétral", "Élévateur de l'anus + coccygien", "Obturateur interne + piriforme"],a:2,e:"Diaphragme PELVIEN (plan profond) = ÉLÉVATEUR DE L'ANUS + COCCYGIEN."},
  {c:"8",l:"Chap. 8",q:"Le diaphragme urogénital est composé de :",o:["Ischiocaverneux + bulbo-spongieux", "Transverse profond + sphincter urétral (+muscles féminins)", "Élévateur de l'anus + coccygien", "Obturateur interne + piriforme"],a:1,e:"Diaphragme UROGÉNITAL (plan intermédiaire) = transverse profond + sphincter urétral (+ sphincter urétro-vaginal + compresseur urétral ♀)."},
  {c:"8",l:"Chap. 8",q:"Le plan superficiel du périnée comprend :",o:["Obturateur interne + piriforme", "Élévateur de l'anus + coccygien", "Transverse profond + sphincter urétral", "Ischiocaverneux + bulbo-spongieux + transverse superf. + sphincter anal"],a:3,e:"Plan SUPERFICIEL périnée = ischiocaverneux + bulbo-spongieux + transverse superficiel + sphincter anal externe."},
  {c:"8",l:"Chap. 8",q:"Le muscle ischio-caverneux prend origine sur :",o:["Membrane obturatrice", "Tubercule médial calcanéum", "Tubérosité + branche ischiatique", "Corps périnéal"],a:2,e:"Ischio-caverneux : TUBÉROSITÉ + branche ischiatique → base pénis/clitoris. Pousse le sang vers les corps érectiles."},
  // CHAP 9 - GROUPES NERVEUX
  {c:"9",l:"Chap. 9",q:"Les plexus somatiques formés par les branches antérieures des nerfs rachidiens sont :",o:["Cervical + brachial + lombaire + sacré", "Cervical + lombaire + sacré", "Lombaire + sacré uniquement", "Cervical + brachial uniquement"],a:0,e:"4 plexus somatiques : CERVICAL + BRACHIAL + LOMBAIRE + SACRÉ. Formés par les branches ANTÉRIEURES des nerfs rachidiens."},
  {c:"9",l:"Chap. 9",q:"Le nerf accessoire (XI) innerve :",o:["Trapèze + SCM", "Muscles de la langue", "Muscles masticateurs", "Muscles mimique"],a:0,e:"NC XI (ACCESSOIRE) = TRAPÈZE + SCM. NC XII (hypoglosse) = muscles langue + thyrohyoïdien + géniohyoïdien."},
  {c:"9",l:"Chap. 9",q:"La dure-mère est la méningée :",o:["La plus vascularisée", "L'intermédiaire", "La plus externe et la plus épaisse", "La plus interne et la plus fine"],a:2,e:"DURE-MÈRE = la plus EXTERNE et la plus ÉPAISSE. Pie-mère = la plus interne (collée à la moelle)."},
  // CHAP 2.2 - LIGAMENTS HANCHE
  {c:"22",l:"Chap. 2.2",q:"Quel ligament de la hanche limite principalement l'extension ?",o:["Ligament pubo-fémoral", "Ligament ischio-fémoral", "Ligament de la tête fémorale", "Ligament ilio-fémoral"],a:3,e:"Lig. ILIO-FÉMORAL (en Y) = limite principalement l'EXTENSION. C'est le lig. le plus solide du corps."},
  {c:"22",l:"Chap. 2.2",q:"Quel ligament de la hanche limite la rotation médiale ?",o:["Ligament de la tête fémorale", "Ligament ilio-fémoral", "Ligament ischio-fémoral", "Ligament pubo-fémoral"],a:2,e:"Lig. ISCHIO-FÉMORAL : bourrelet post. → face ant. fémur. Limite la ROTATION MÉDIALE."},
  {c:"22",l:"Chap. 2.2",q:"L'obturateur interne réalise :",o:["Rotation méd. + antéversion", "Rotation lat. + rétroversion bassin", "Adduction + rotation lat.", "Abduction + rotation méd."],a:1,e:"Obturateur interne : ROTATION LAT. + rétroversion bassin. Innervé par nerf obturateur interne L5–S1."},
  {c:"22",l:"Chap. 2.2",q:"Les muscles rotateurs latéraux profonds de la hanche sont :",o:["Piriforme + jumeaux + obturateurs + carré fémoral", "Adducteurs + gracile + pectiné", "Grand glutéal + moyen glutéal + TFL", "Psoas + iliaque + sartorius"],a:0,e:"Rotateurs LAT. profonds = PIRIFORME + JUMEAUX sup./inf. + OBTURATEURS int./ext. + CARRÉ FÉMORAL."},
  // CHAP 2.3 - LIGAMENTS GENOU
  {c:"23",l:"Chap. 2.3",q:"Quel ligament du genou limite la rotation MÉDIALE ?",o:["LCA", "LCP", "LCL", "LCM"],a:2,e:"LCL (ligament collatéral LATÉRAL) : épicondyle lat. fémur → tête fibulaire. Limite VARUS + rotation MÉDIALE."},
  {c:"23",l:"Chap. 2.3",q:"Quel ligament du genou limite la translation POSTÉRIEURE du tibia ?",o:["LCP", "LCA", "LCL", "LCM"],a:0,e:"LCP (ligament croisé POSTÉRIEUR) : limite la translation POSTÉRIEURE du tibia. C'est le plus solide des 2 croisés."},
  {c:"23",l:"Chap. 2.3",q:"La 'triade malheureuse' du genou associe :",o:["LCA + LCM + ménisque méd.", "LCP + LCL + ménisque lat.", "LCA + LCP + ménisque lat.", "LCM + LCL + ménisque méd."],a:0,e:"Triade malheureuse = LCA + LCM + MÉNISQUE MÉDIAL. Le LCM adhère au ménisque méd. → lésion combinée lors de valgus forcé."},
  {c:"23",l:"Chap. 2.3",q:"Quel mouvement est limité par le plan fibreux postérieur du genou ?",o:["L'hyperextension", "La rotation médiale", "La flexion", "La rotation latérale"],a:0,e:"Plan fibreux POST. (lig. poplité oblique + arqué) : limite l'HYPEREXTENSION du genou."},
  // CHAP 2.5 - GROUPES MUSCULAIRES CUISSE
  {c:"25",l:"Chap. 2.5",q:"La loge ANTÉRIEURE de la cuisse contient :",o:["Ischio-jambiers + biceps fémoral", "Quadriceps + sartorius", "Grand adducteur + gracile", "Adducteurs + gracile + pectiné"],a:1,e:"Loge ANTÉRIEURE = QUADRICEPS + SARTORIUS. Innervation = nerf FÉMORAL."},
  {c:"25",l:"Chap. 2.5",q:"La loge MÉDIALE de la cuisse contient, en plan superficiel :",o:["Tous les adducteurs", "Pectiné + long adducteur + gracile", "Court adducteur uniquement", "Grand adducteur + obturateur ext."],a:1,e:"Loge méd. plan SUPERFICIEL = PECTINÉ + LONG ADDUCTEUR + GRACILE. Plan moyen = court adducteur. Plan profond = grand add. + obturateur ext."},
  {c:"25",l:"Chap. 2.5",q:"Les ischio-jambiers sont :",o:["Tous monoarticulaires", "Monoarticulaires (genou uniquement)", "Biarticulaires sauf le chef court du biceps", "Tous biarticulaires"],a:2,e:"Ischio-jambiers BIARTICULAIRES sauf le CHEF COURT du biceps fémoral (ne s'insère que sur la ligne âpre → genou uniquement)."},
  {c:"25",l:"Chap. 2.5",q:"Le semi-membraneux s'insère via son tendon DIRECT sur :",o:["La patte d'oie superficielle", "Le ligament poplité oblique", "La patte d'oie profonde uniquement", "La partie postérieure du condyle médial tibia"],a:3,e:"Semi-membraneux : tendon DIRECT → partie POST. condyle MÉDIAL tibia. Tendon récurrent → lig. poplité oblique. Tendon réfléchi → partie ant. condyle méd. tibia."},
  // CHAP 2.6 - MUSCLES JAMBE GROUPES
  {c:"26",l:"Chap. 2.6",q:"Le groupe POSTÉRIEUR PROFOND de la jambe comprend :",o:["Long fibulaire + court fibulaire", "Tibial ant. + long ext. orteils + long ext. hallux", "Gastrocnémien + soléaire + plantaire", "Poplité + long fléch. orteils + long fléch. hallux + tibial post."],a:3,e:"Groupe post. PROFOND = POPLITÉ + long fléch. orteils + long fléch. hallux + TIBIAL POSTÉRIEUR. Plan superf. = triceps sural + plantaire."},
  {c:"26",l:"Chap. 2.6",q:"Quel muscle du groupe postérieur profond réalise l'inversion du pied ?",o:["Long fléchisseur de l'hallux", "Long fléchisseur des orteils", "Tibial postérieur", "Poplité"],a:2,e:"TIBIAL POSTÉRIEUR = principale action INVERSION du pied. Origine : membrane interosseuse + tibia + fibula."},
  {c:"26",l:"Chap. 2.6",q:"Le triceps sural est composé de :",o:["Gastrocnémien + poplité + soléaire", "Gastrocnémien + soléaire + plantaire", "Soléaire + plantaire + tibial post.", "Gastrocnémien + soléaire uniquement"],a:3,e:"Triceps sural = GASTROCNÉMIEN + SOLÉAIRE. Le plantaire est un muscle distinct (mais souvent associé)."},
  {c:"26",l:"Chap. 2.6",q:"Le soléaire prend origine sur :",o:["Condyles fémoraux méd. et lat.", "Face post. fibula uniquement", "Condyle lat. fémur", "Ligne du soléaire tibia + face post. tête fibula + arc tendineux"],a:3,e:"Soléaire : ligne du soléaire + bord méd. tibia + face post. TÊTE fibula + ARC TENDINEUX entre les 2 insertions."},
  {c:"26",l:"Chap. 2.6",q:"Les rétinaculums de la cheville servent à :",o:["Renforcer les ligaments de la cheville", "Limiter les mouvements de la cheville", "Maintenir les tendons en position et agissent comme poulies", "Protéger les vaisseaux de la cheville"],a:2,e:"Rétinaculums = épaississements de l'aponévrose profonde → MAINTIENNENT LES TENDONS + agissent comme POULIES."},
  // CHAP 2.7 - GROUPES MUSCLES PIED
  {c:"27",l:"Chap. 2.7",q:"Le groupe MÉDIAL du pied contient :",o:["Fléch. 5e + opposant 5e + abducteur 5e", "Interosseux + carré plantaire + lombricaux", "Court fléch. hallux + adducteur hallux + abducteur hallux", "Court ext. orteils + court ext. hallux"],a:2,e:"Groupe MÉDIAL = court fléch. hallux + adducteur hallux + ABDUCTEUR hallux."},
  {c:"27",l:"Chap. 2.7",q:"Le groupe LATÉRAL du pied contient :",o:["Court ext. orteils + court ext. hallux", "Fléch. 5e orteil + opposant 5e + abducteur 5e", "Court fléch. orteils + lombricaux", "Interosseux + carré plantaire"],a:1,e:"Groupe LATÉRAL = fléch. 5e + opposant 5e + ABDUCTEUR 5e (plan prof. + plan superf.)."},
  {c:"27",l:"Chap. 2.7",q:"L'innervation du groupe dorsal du pied est assurée par :",o:["Nerf plantaire médial", "Nerf tibial", "Nerf fibulaire profond", "Nerf fibulaire superficiel"],a:2,e:"Groupe DORSAL (court ext. orteils + court ext. hallux) = nerf FIBULAIRE PROFOND."},
  {c:"27",l:"Chap. 2.7",q:"Les interosseux PLANTAIRES déplacent les orteils :",o:["Latéralement (abduction)", "En flexion plantaire", "Médialement (adduction)", "En extension"],a:2,e:"Interosseux PLANTAIRES = 3 muscles → déplacement MÉDIAL (adduction). Dorsaux = 4 muscles → déplacement latéral."},
  // CHAP 2.8 - GROUPES NERVEUX MI
  {c:"28",l:"Chap. 2.8",q:"Le nerf sciatique se divise en ses 2 branches terminales au niveau :",o:["Du grand foramen sciatique", "De la tête fibulaire", "Du canal de Hunter", "Du creux poplité"],a:3,e:"Nerf sciatique se divise en nerf TIBIAL + nerf FIBULAIRE COMMUN au niveau du CREUX POPLITÉ."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf saphène innerve en sensitif :",o:["La plante du pied", "La face médiale de la jambe et du pied", "La face dorsale du pied", "La face latérale de la jambe"],a:1,e:"Nerf saphène (branche sensitive nerf fémoral) = face MÉDIALE de la JAMBE ET DU PIED."},
  {c:"28",l:"Chap. 2.8",q:"Le nerf glutéal supérieur passe :",o:["En dessous du piriforme", "Au-dessus du piriforme", "En dessous du lig. sacro-tubéreux", "À travers le piriforme"],a:0,e:"Nerf glutéal SUPÉRIEUR passe EN DESSOUS du piriforme (dans le grand foramen sciatique, au-dessus pour le glutéal inf.)."},
  {c:"28",l:"Chap. 2.8",q:"Quel nerf innerve le muscle piriforme ?",o:["Nerf obturateur interne", "Nerf glutéal inférieur", "Nerf glutéal supérieur", "Nerf du piriforme (branche directe plexus sacré)"],a:3,e:"Piriforme = nerf du PIRIFORME, branche directe du plexus SACRÉ."},
  {c:"28",l:"Chap. 2.8",q:"La zone médiale de la jambe est innervée par :",o:["Nerf tibial", "Nerf saphène", "Nerf fibulaire profond", "Nerf fibulaire superficiel"],a:3,e:"Zone MÉDIALE jambe = nerf FIBULAIRE SUPERFICIEL (comme la zone latérale). Zone ant. = fibulaire profond. Zone post. = tibial."},
  // BONUS - QUESTIONS MIXTES TYPE PARTIEL
  {c:"22",l:"Chap. 2.2",q:"La surface articulaire de l'acétabulum en contact avec la tête fémorale est :",o:["Le labrum acétabulaire", "La fosse acétabulaire", "La surface semi-lunaire", "L'incisure acétabulaire"],a:2,e:"SURFACE SEMI-LUNAIRE = surface cartilagineuse de l'acétabulum qui s'articule avec la tête fémorale. La fosse = remplie de graisse (non articulaire)."},
  {c:"23",l:"Chap. 2.3",q:"Le ménisque latéral N'adhère PAS au LCL. Quelle en est la conséquence ?",o:["Il est plus mobile et moins souvent lésé", "Il est plus épais", "Il est plus souvent lésé", "Il est moins vascularisé"],a:0,e:"Ménisque LAT. N'adhère PAS au LCL → PLUS MOBILE → MOINS SOUVENT LÉSÉ. (Ménisque méd. adhère au LCM → moins mobile → plus souvent lésé)."},
  {c:"26",l:"Chap. 2.6",q:"Le ligament deltoïde (médial) de la cheville comprend :",o:["3 faisceaux", "2 faisceaux", "5 faisceaux", "4 faisceaux (tibio-naviculaire + tibio-calcanéen + tibio-talaire ant. + post.)"],a:3,e:"Lig. DELTOÏDE = 4 FAISCEAUX : tibio-NAVICULAIRE + tibio-CALCANÉEN + tibio-talaire ANT. + tibio-talaire POST."},
  {c:"26",l:"Chap. 2.6",q:"L'articulation talo-crurale réalise EXCLUSIVEMENT :",o:["Flexion plantaire et dorsale uniquement", "Inversion + éversion uniquement", "Rotation + flexion plantaire", "Flexion/extension + inversion/éversion"],a:0,e:"Talo-crurale = articulation très fermée → FLEXION PLANTAIRE + DORSALE EXCLUSIVEMENT. L'inversion/éversion = articulation SOUS-TALIENNE."},
  {c:"5",l:"Chap. 5",q:"L'ATM permet combien de types de mouvements ?",o:["6", "3", "4", "5"],a:3,e:"ATM permet 5 mouvements : DESCENTE + ASCENSION + PROPULSION + RÉTROPULSION + LATÉRALITÉ (diduction)."},
  {c:"7",l:"Chap. 7",q:"Les muscles larges de l'abdomen participent à :",o:["Soutien viscères + presse abdominale + respiration + toux + défécation + accouchement", "Uniquement soutien des viscères et flexion", "Soutien viscères + rotation uniquement", "Soutien viscères + extension"],a:0,e:"Muscles larges : soutien viscères + PRESSE ABDOMINALE + respiration + toux + défécation + accouchement."},
  {c:"3",l:"Chap. 3",q:"Les muscles sous-occipitaux sont tous innervés par :",o:["Nerf hypoglosse XII", "Branche post. C1", "Nerf grand occipital d'Arnold", "Branche post. C2"],a:1,e:"Les 4 sous-occipitaux = branche POST. de C1. Le nerf d'Arnold (C2) = SENSITIF uniquement (cuir chevelu post.)."}
];

